241	        {
242	            // 需要增加符號
243	            for ( let row = this.m_nodeCount; row < newCount; ++row )
244	            {
245	                let singleCell = new SingleCell(this.m_parentNode, this.m_gameView, this.m_name, row);
246	                singleCell.SetSymbolShow( false ); // 預設隱藏，等待設定符號時顯示
247	                this.m_singleCells[ row ] = singleCell;
248	            }
249	        }
250	        else
251	        {
252	            // 需要減少符號 - 隱藏多餘的符號
253	            for ( let row = newCount; row < this.m_nodeCount; ++row )
254	            {
255	                if ( row < this.m_singleCells.length )
256	                {
257	                    this.m_singleCells[ row ].SetSymbolShow( false );
258	                }
259	            }
260	        }
261	        
262	        this.m_nodeCount = newCount;
