269	    private ResetAllSymbolPositions()
270	    {
271	        for ( let row = 0; row < this.m_symbols.length && row < this.m_nodeCount; ++row )
272	        {
273	            if ( row < this.m_singleCells.length )
274	            {
275	                this.m_singleCells[ row ].SetPosition( this.CalPosY( row ) );
276	            }
277	        }
