291	        return -1; // 無效位置
292	    }
293	    
294	    /**
295	     * @ch 設定特定位置的符號ID
296	     * @param row 要設定的行
297	     * @param symbolId 要設定的符號ID
298	     */
299	    SetSymbolAt( row: number, symbolId: number )
300	    {
