351	     * @ch 取得特定位置的Node
352	     * @param row 要取得的行
353	     * @returns Node
354	     */
355	    GetSymbolSingleCellAt( row: number ): SingleCell
356	    {
357	        if ( row >= 0 && row < this.m_symbols.length && row < this.m_singleCells.length )
358	        {
359	            return this.m_singleCells[ row ];
360	        }
361	        return null; // 無效位置
362	    }
363	
364	    FillSymbol( )
365	    {
366	
367	       
368	
369	        class TempSymbolData
370	        {
371	            public symbolID: number;
372	            public symbolInfo: SymbolInfo;
373	            public pos: Vec3;
374	            public isShow: boolean;
375	
376	        }
377	
378	        let fillSymbols: TempSymbolData[] = [];
379	        let leftSymbols: TempSymbolData[] = [];
380	        for(let i = this.m_singleCells.length-1; i >= 0; i--)
381	        {
382	            if(this.m_singleCells[i].ThisNode.active)
383	            {
384	                let symbolInfo = new SymbolInfo();
385	                symbolInfo.Symbol = this.m_symbols[i];
386	                symbolInfo.Value = 0;
387	                symbolInfo.JpType = 0;
388	                
389	                let tempSymbolData = new TempSymbolData();
390	                tempSymbolData.symbolID = this.m_symbols[i];
391	                tempSymbolData.symbolInfo = symbolInfo;
392	                tempSymbolData.pos = this.m_singleCells[i].ThisNode.position;
393	                tempSymbolData.isShow = true;
394	                
395	                leftSymbols.push(tempSymbolData);
396	                
397	            }
398	            else
399	            {
400	                let symbolInfo = new SymbolInfo();
401	                symbolInfo.Symbol = this.m_symbols[i];
402	                symbolInfo.Value = 0;
403	                symbolInfo.JpType = 0;
404	                
405	                let tempSymbolData = new TempSymbolData();
406	                tempSymbolData.symbolID = this.m_symbols[i];
407	                tempSymbolData.symbolInfo = symbolInfo;
408	                tempSymbolData.pos = this.m_singleCells[i].ThisNode.position;
409	                tempSymbolData.isShow = false;
410	                fillSymbols.push(tempSymbolData);
411	            }
412	        }
413	
414	        for(let i = this.m_singleCells.length-1; i >= 0; i--)
415	        {
416	            if(leftSymbols.length > 0)
417	            {
418	                let tempSymbolData = leftSymbols.shift();
419	                this.m_singleCells[i].ChangeSymbol( tempSymbolData.symbolInfo );
420	                this.m_singleCells[i].SetSymbolShow( tempSymbolData.isShow );
421	                this.m_singleCells[i].ThisNode.setPosition( tempSymbolData.pos );
422	                this.m_symbols[i] = tempSymbolData.symbolID;
423	            }
424	            else
425	            {
426	                let tempSymbolData = fillSymbols.shift();
427	                this.m_singleCells[i].ChangeSymbol( tempSymbolData.symbolInfo );
428	                this.m_singleCells[i].SetSymbolShow( tempSymbolData.isShow );
429	
430	                this.m_symbols[i] = tempSymbolData.symbolID;
431	            }
432	        }
433	
434	        
435	    }
