438	    {
439	
440	        let symbolInfo = new SymbolInfo();
441	        symbolInfo.Symbol = symbolId;
442	        symbolInfo.Value = 0;
443	        symbolInfo.JpType = 0;  
444	        symbol.ChangeSymbol( symbolInfo );
445	        symbol.SetSymbolShow( true );
446	        this.m_symbols[id] = symbolId;
447	
