import { _decorator, Node, v3, Vec3, SpriteFrame, log } from "cc";
import Game_Define, { SymbolInfo } from "./Game_Define";
import GameView from "./GameView";
import { SingleCell } from "./SingleCell";

const { ccclass } = _decorator;
@ccclass( "ColumnSymbol" )
export class ColumnSymbol
{
    private m_parentNode: Node = null;
    private m_singleCells: Array<SingleCell> = new Array<SingleCell>();
    private m_gameView: GameView = null;
    private m_symbols: number[] = [];
    private m_nodeCount: number = Game_Define.ROW;
    private m_getSpriteFrame: (symbolId: number) => SpriteFrame = null;

    /**
     * @ch 獲取符號陣列
     * @returns 符號陣列
     */
    public get Symbols()
    {
        return this.m_symbols;
    }

    /**
     * @ch 獲取節點數量
     * @returns 節點數量
     */
    public get NodeCount()
    {
        return this.m_nodeCount;
    }

    private m_name: string = "";
    /**
     * @ch 獲取列名
     * @returns 列名
     */
    public get Name()
    {
        return this.m_name;
    }
    /**
     * @ch 設定列名
     * @param v 列名
     */
    public set Name( v: string )
    {
        this.m_name = v;
    }

    private m_basePos: Vec3 = v3( 0, 0, 0 );

    /**
     * @ch 將每個column的每個row都設定可能出現的東西(sprite, prefab)
     * @param parent 父節點
     * @param gameView 遊戲視圖
     * @param name 列名
     * @param nodeCount 節點數量
     * @param getSpriteFrame 獲取SpriteFrame的函數
     * @param layer 圖層
     */
    constructor( 
        parent: Node, 
        gameView: GameView, 
        name: string, 
        nodeCount?: number,
        getSpriteFrame?: (symbolId: number) => SpriteFrame,
        layer?: number
    )
    {
        this.m_parentNode = parent;
        this.m_gameView = gameView;

        this.m_nodeCount = nodeCount;

        this.m_getSpriteFrame = getSpriteFrame || ((symbolId: number) => this.m_gameView.GetSymbolSpriteFrame(symbolId));

        for ( let row = 0; row < this.m_nodeCount; ++row )
        {
            let singleCell = new SingleCell(this.m_parentNode, this.m_gameView, name, row);
            this.m_singleCells[ row ] = singleCell;
        }
    }

    /**
     * @ch 設定要顯示在盤面上的symbol資訊
     * @param symbolInfos 要顯示的symbol資訊
     * @param isResetPosition 是否重置位置
     */
    SetSymbolInfos( symbolInfos: SymbolInfo[], isResetPosition: boolean = true )
    {
        // 更新symbols陣列以保持相容性
        this.m_symbols = symbolInfos.map( info => info.Symbol );

        for ( let row = 0; row < this.m_singleCells.length; ++row )
        {
            // 有些遊戲每個Column的symbol數量不一定
            if ( row < symbolInfos.length )
            {
                this.m_singleCells[ row ].SetSymbolShow( true );
                this.m_singleCells[ row ].SetInfo( symbolInfos[ row ] );
                if (isResetPosition) {
                    this.m_singleCells[ row ].SetPosition( this.CalPosY( row ) );
                }
            }
            else
            {
                this.m_singleCells[ row ].SetSymbolShow( false );
            }
        }
    }

    /**
     * @ch 置換Symbol
     * @param symbol 要置換的Symbol
     * @param row 要置換的行
     */
    ChangeSymbol( symbol: number, row: number )
    {
        if ( row < this.m_singleCells.length )
        {
            let symbolInfo = new SymbolInfo();
            symbolInfo.Symbol = symbol;
            symbolInfo.Value = 0;
            symbolInfo.JpType = 0;

            this.m_singleCells[ row ].ChangeSymbol( symbolInfo );
            this.m_singleCells[ row ].SetSymbolShow( true );
        }
    }

    /**
     * @ch 置換Symbol資訊
     * @param symbolInfo 要置換的Symbol資訊
     * @param row 要置換的行
     */
    ChangeSymbolInfo( symbolInfo: SymbolInfo, row: number )
    {
        if ( row < this.m_singleCells.length )
        {
            this.m_singleCells[ row ].ChangeSymbol( symbolInfo );
            this.m_singleCells[ row ].SetSymbolShow( true );
        }
    }

    /**
     * @ch 設定位置
     * @param pos 要設定的位置
     */
    SetPosition( pos: Vec3 )
    {
        this.m_basePos = pos;
        for ( let row = 0; row < this.m_symbols.length; ++row )
        {
            let pos = this.CalPosY( row );

            this.m_singleCells[ row ].SetPosition( pos );
        }
    }

    /**
     * @ch 計算Y軸座標，要用clone不然會被pos戳到
     * @param row 要計算的行
     * @returns 計算後的Y軸座標
     */
    CalPosY( row: number ): Vec3
    {
        let pos = this.m_basePos.clone();
        // 因為上下顛倒，這邊用減的，使用動態的nodeCount
        pos.y += ( this.m_nodeCount - 1 - row + 0.5 ) * Game_Define.SymbolHeight;
        return pos;
    }

    /**
     * @ch 計算靜止時Y軸座標，多用一個靜止的，省得被其他東西戳到
     * @param row 要計算的行
     * @returns 計算後的Y軸座標
     */
    CalStopPosY( row: number ): Vec3
    {
        let pos = v3( 0, 0, 0 );
        // 因為上下顛倒，這邊用減的，使用動態的nodeCount
        pos.y += ( this.m_nodeCount - 2.5 - row + 0.5 ) * Game_Define.SymbolHeight;
        return pos;
    }

    /**
     * @ch 設定特定位置的Symbol是否顯示
     * @param row 行索引 (0 ~ Game_Define.ROW-1)
     * @param isShow 是否顯示
     */
    SetSymbolShow( row: number, isShow: boolean )
    {
        if ( row < this.m_singleCells.length )
        {
            this.m_singleCells[ row ].SetSymbolShow( isShow );
        }
    }

    /**
     * @ch 顯示此Col
     * @param isShow 是否顯示
     */
    SetColumnShow( isShow: boolean )
    {
        for ( let i = 0; i < this.m_nodeCount; ++i )
        {
            this.SetSymbolShow( i, isShow );
        }
    }

    /**
     * @ch 壓黑此Col
     * @param setToDark 是否壓黑
     */
    SetSymbolDark( setToDark: boolean )
    {
        for ( let i = 0; i < this.m_nodeCount; ++i )
        {
            if ( i < this.m_singleCells.length )
            {
                this.m_singleCells[ i ].SetSymbolDark( setToDark );
            }
        }
    }

    /**
     * @ch 動態調整符號數量 - 彈性轉輪系統新增
     * @param newCount 新的符號數量
     */
    ResizeSymbolCount( newCount: number )
    {
        if ( newCount === this.m_nodeCount )
        {
            return; // 數量相同，無需調整
        }

        if ( newCount > this.m_nodeCount )
        {
            // 需要增加符號
            for ( let row = this.m_nodeCount; row < newCount; ++row )
            {
                let singleCell = new SingleCell(this.m_parentNode, this.m_gameView, this.m_name, row);
                singleCell.SetSymbolShow( false ); // 預設隱藏，等待設定符號時顯示
                this.m_singleCells[ row ] = singleCell;
            }
        }
        else
        {
            // 需要減少符號 - 隱藏多餘的符號
            for ( let row = newCount; row < this.m_nodeCount; ++row )
            {
                if ( row < this.m_singleCells.length )
                {
                    this.m_singleCells[ row ].SetSymbolShow( false );
                }
            }
        }

        this.m_nodeCount = newCount;

        // 重新計算並設定所有符號的位置
        this.ResetAllSymbolPositions();
    }

    /**@ch 重新計算所有符號位置 */
    private ResetAllSymbolPositions()
    {
        for ( let row = 0; row < this.m_symbols.length && row < this.m_nodeCount; ++row )
        {
            if ( row < this.m_singleCells.length )
            {
                this.m_singleCells[ row ].SetPosition( this.CalPosY( row ) );
            }
        }
    }

    /**
     * @ch 取得特定位置的符號ID
     * @param row 要取得的行
     * @returns 符號ID
     */
    GetSymbolAt( row: number ): number
    {
        if ( row >= 0 && row < this.m_symbols.length )
        {
            return this.m_symbols[ row ];
        }
        return -1; // 無效位置
    }

    /**
     * @ch 設定特定位置的符號ID
     * @param row 要設定的行
     * @param symbolId 要設定的符號ID
     */
    SetSymbolAt( row: number, symbolId: number )
    {
        if ( row >= 0 && row < this.m_symbols.length )
        {
            this.m_symbols[ row ] = symbolId;
            this.ChangeSymbol( symbolId, row );
        }
    }

    /**
     * @ch 設定特定位置的符號資訊
     * @param row 要設定的行
     * @param symbolInfo 要設定的符號資訊
     */
    SetSymbolInfoAt( row: number, symbolInfo: SymbolInfo )
    {
        if ( row >= 0 && row < this.m_symbols.length )
        {
            this.m_symbols[ row ] = symbolInfo.Symbol;
            this.ChangeSymbolInfo( symbolInfo, row );
        }
    }

    /**
     * @ch 取得特定位置的Node
     * @param row 要取得的行
     * @returns Node
     */
    GetSymbolNodeAt( row: number ): Node
    {
        if ( row >= 0 && row < this.m_symbols.length && row < this.m_singleCells.length )
        {
            return this.m_singleCells[ row ].ThisNode;
        }
        return null; // 無效位置
    }

    /**
     * @ch 取得特定位置的 SingleCell
     * @param row 要取得的行
     * @returns SingleCell
     */
    GetSingleCell( row: number ): SingleCell
    {
        if ( row >= 0 && row < this.m_singleCells.length )
        {
            return this.m_singleCells[ row ];
        }
        return null; // 無效位置
    }

    /**
     * @ch 取得特定位置的Node
     * @param row 要取得的行
     * @returns Node
     */
    GetSymbolSingleCellAt( row: number ): SingleCell
    {
        if ( row >= 0 && row < this.m_symbols.length && row < this.m_singleCells.length )
        {
            return this.m_singleCells[ row ];
        }
        return null; // 無效位置
    }

    FillSymbol( )
    {



        class TempSymbolData
        {
            public symbolID: number;
            public symbolInfo: SymbolInfo;
            public pos: Vec3;
            public isShow: boolean;

        }

        let fillSymbols: TempSymbolData[] = [];
        let leftSymbols: TempSymbolData[] = [];
        for(let i = this.m_singleCells.length-1; i >= 0; i--)
        {
            if(this.m_singleCells[i].ThisNode.active)
            {
                let symbolInfo = new SymbolInfo();
                symbolInfo.Symbol = this.m_symbols[i];
                symbolInfo.Value = 0;
                symbolInfo.JpType = 0;

                let tempSymbolData = new TempSymbolData();
                tempSymbolData.symbolID = this.m_symbols[i];
                tempSymbolData.symbolInfo = symbolInfo;
                tempSymbolData.pos = this.m_singleCells[i].ThisNode.position;
                tempSymbolData.isShow = true;

                leftSymbols.push(tempSymbolData);

            }
            else
            {
                let symbolInfo = new SymbolInfo();
                symbolInfo.Symbol = this.m_symbols[i];
                symbolInfo.Value = 0;
                symbolInfo.JpType = 0;

                let tempSymbolData = new TempSymbolData();
                tempSymbolData.symbolID = this.m_symbols[i];
                tempSymbolData.symbolInfo = symbolInfo;
                tempSymbolData.pos = this.m_singleCells[i].ThisNode.position;
                tempSymbolData.isShow = false;
                fillSymbols.push(tempSymbolData);
            }
        }

        for(let i = this.m_singleCells.length-1; i >= 0; i--)
        {
            if(leftSymbols.length > 0)
            {
                let tempSymbolData = leftSymbols.shift();
                this.m_singleCells[i].ChangeSymbol( tempSymbolData.symbolInfo );
                this.m_singleCells[i].SetSymbolShow( tempSymbolData.isShow );
                this.m_singleCells[i].ThisNode.setPosition( tempSymbolData.pos );
                this.m_symbols[i] = tempSymbolData.symbolID;
            }
            else
            {
                let tempSymbolData = fillSymbols.shift();
                this.m_singleCells[i].ChangeSymbol( tempSymbolData.symbolInfo );
                this.m_singleCells[i].SetSymbolShow( tempSymbolData.isShow );

                this.m_symbols[i] = tempSymbolData.symbolID;
            }
        }


    }

    ReFillSymbol( symbol: SingleCell, symbolId: number, id:number )
    {

        let symbolInfo = new SymbolInfo();
        symbolInfo.Symbol = symbolId;
        symbolInfo.Value = 0;
        symbolInfo.JpType = 0;  
        symbol.ChangeSymbol( symbolInfo );
        symbol.SetSymbolShow( true );
        this.m_symbols[id] = symbolId;

    }
}

