import { _decorator, Node, Vec3, v3, Sprite, Layers } from 'cc';
import Game_Define, { SymbolInfo } from "./Game_Define";
import { Define, tools } from "db://astarte-framework/utilis";
import GameView from './GameView';

/**
 * 安全地使用 tools.strip 方法的輔助函數
 * @param value 要處理的數值
 * @param precision 精度（可選）
 * @returns 處理後的數值
 */
function safeStrip(value: number, precision?: number): number {
    try {
        // 確保 value 是有效的數字
        if (typeof value !== 'number' || isNaN(value)) {
            console.warn('[safeStrip] 無效的數值:', value);
            return 0;
        }

        // 優先使用 tools.strip 方法
        if (tools && typeof tools.strip === 'function') {
            const result = tools.strip(value, precision);
            // 檢查結果是否有效
            if (typeof result === 'number' && !isNaN(result)) {
                return result;
            }
        }

        // 備用方法：使用 parseFloat 和 toPrecision 來處理精度問題
        const defaultPrecision = precision !== undefined ? precision : 12;
        return parseFloat(value.toPrecision(defaultPrecision));
    } catch (error) {
        console.error('[safeStrip] 錯誤:', error, '數值:', value);
        return value; // 返回原值作為最後備用
    }
}

const SINGLE_ROW = 1;

/**@ch 下轉輪數 */
const LOWER_PLATES = 1;

const ANCHOR_POINT = 0;

const { ccclass } = _decorator;
@ccclass('SingleCell')
export class SingleCell
{
    private m_parentNode: Node = null;
    private m_symbolSprite: Sprite = null;


    private m_thisNode: Node = null;
    public get ThisNode()
    {
        return this.m_thisNode;
    }
    private m_gameView: GameView = null;
    private m_name: string = "";
    public get Name()
    {
        return this.m_name;
    }
    public set Name(v: string)
    {
        this.m_name = v;
    }

    private m_basePos: Vec3 = v3(0, 0, 0);

    private m_symbolId: number = -1;

    constructor(parent: Node, gameView: GameView, name: string, col: number) 
    {
        this.m_parentNode = parent;
        this.m_gameView = gameView;
        let node = new Node();
        node.name = name + col.toString();
        this.Name = node.name;
        node.layer = Layers.Enum.DEFAULT; //Define.Layer2D;

        // 創建額外的 sprite


        let spriteNode = new Node();
        spriteNode.name = "Sprite";
        spriteNode.layer = Layers.Enum.DEFAULT; //Define.Layer2D;
        let symbolSprite: Sprite = spriteNode.addComponent( Sprite );
        symbolSprite.type = Sprite.Type.SIMPLE;
        symbolSprite.sizeMode = Sprite.SizeMode.RAW;
        symbolSprite.trim = false;
        node.addChild(spriteNode);
        this.m_symbolSprite = symbolSprite;

        this.m_parentNode.addChild(node);
        this.m_thisNode = node;
    }

    /**@ch 設定symbol及其info */
    SetInfo( info: SymbolInfo )
    {
        this.ChangeSymbol( info );
        this.m_thisNode.setPosition( this.CalPosY() );
    }

    /**@ch 更換symbol */
    ChangeSymbol(info: SymbolInfo)
    {

        this.m_symbolSprite.spriteFrame = this.m_gameView.GetSymbolSpriteFrame( info.Symbol );
        this.m_symbolId = info.Symbol;

        // 設置symbol背景

    }

    /**@ch 設定位置 */
    SetPosition(pos: Vec3)
    {
        this.m_basePos = pos;
        let pos2 = this.CalPosY();
        this.m_thisNode.setPosition(pos2);
    }

    /**@ch 計算Y軸座標 */
    CalPosY( row: number = 0 ): Vec3
    {
        let pos = this.m_basePos.clone();// 要用clone不然會被pos戳到
        pos.y += ( SINGLE_ROW - LOWER_PLATES - row + ANCHOR_POINT ) * Game_Define.SymbolHeight;
        return pos;
    }

    /**@ch 壓黑此Cell */
    SetSymbolDark( setToDark: boolean )
    {
        let color = setToDark && Game_Define.IsDarkSymbolBlackMask(this.m_symbolId) ? Game_Define.Color.Dark : Game_Define.Color.Light;
        this.m_symbolSprite.color = color;
    }

    /**@ch 顯示此symbol */
    SetSymbolShow( v: boolean )
    {
        this.m_thisNode.active = v;
    }

    /**@ch 取得Node */
    GetNode(): Node
    {
        return this.m_thisNode;
    }
}

