import { _decorator, Component, EventKeyboard, Input, input, KeyCode, log, Node, Sprite } from 'cc';
import { eventManager } from 'db://astarte-framework/Managers';
import { Common } from '../Common/Common';
import { SymbolBlackMask } from './SymbolBlackMask';
import GameView from '../GameView';
import Game_Define from '../Game_Define';
import { DEBUG } from 'cc/env';
const { ccclass, property } = _decorator;

/**@ch UI Type*/
export enum UIType {
    MainGame = 0,
    FreeGame = 1,
    BonusGame = 2
}

/**@ch ReelUI Manager 事件*/
export const REEL_UI_MANAGER_EVENT = {

    /**
     * @ch 初始化
     * @param gameView 遊戲視窗
     */
    INIT: "REEL_UI_MANAGER_INIT",

    /**
     * @ch 更改UI
     * @param UIType or number UI類型 (0: 主遊戲, 1: 免費遊戲 2:Bonus遊戲)
     */
    CHANGE_UI: "REEL_UI_MANAGER_CHANGE_UI",

    /**
     * @ch 展示UI
     */
    SHOW: "REEL_UI_MANAGER_SHOW",

    /**
     * @ch 隱藏UI
     */
    HIDE: "REEL_UI_MANAGER_HIDE",

    /**
     * @ch 展示黑幕
     */
    SHOW_BLACK_MASK: "REEL_UI_MANAGER_SHOW_BLACK_MASK",

    /**
     * @ch 隱藏黑幕
     */
    HIDE_BLACK_MASK: "REEL_UI_MANAGER_HIDE_BLACK_MASK",

    /**
     * @ch 設定符號黑幕顯示狀態
     * @param pos 位置
     * @param isShow 顯示狀態
     * @param isDark 是否為暗色
     */
    SET_SYMBOL_BLACK_MASK_SHOW: "REEL_UI_MANAGER_SET_SYMBOL_BLACK_MASK_SHOW",

    /**
     * @ch 設定所有符號黑幕顯示狀態
     * @param isShow 顯示狀態
     * @param isDark 是否為暗色
     */
    SET_ALL_SYMBOL_BLACK_MASK_SHOW: "REEL_UI_MANAGER_SET_ALL_SYMBOL_BLACK_MASK_SHOW",

    /**
     * @ch 更新Logo圖片
     */
    UPDATE_LOGO: "REEL_UI_MANAGER_UPDATE_LOGO",
}

@ccclass('ReelUIManager')
export class ReelUIManager extends Component {
    //#region Constants
    /**
     * @ch 需要註冊的事件列表
     */
    private static readonly EVENTS_TO_REGISTER = [
        REEL_UI_MANAGER_EVENT.INIT,
        REEL_UI_MANAGER_EVENT.CHANGE_UI,
        REEL_UI_MANAGER_EVENT.SHOW,
        REEL_UI_MANAGER_EVENT.HIDE,
        REEL_UI_MANAGER_EVENT.SHOW_BLACK_MASK,
        REEL_UI_MANAGER_EVENT.HIDE_BLACK_MASK,
        REEL_UI_MANAGER_EVENT.UPDATE_LOGO,
        REEL_UI_MANAGER_EVENT.SET_SYMBOL_BLACK_MASK_SHOW,
        REEL_UI_MANAGER_EVENT.SET_ALL_SYMBOL_BLACK_MASK_SHOW,
    ];

    /**
     * @ch 符號黑幕透明度（0~255）
     */
    private static readonly SYMBOL_BLACK_MASK_OPACITY_DARK = 200;
    private static readonly SYMBOL_BLACK_MASK_OPACITY_LIGHT = 150;
    //#endregion Constants

    //#region Properties
    @property({
        type: Node,
        tooltip: "根節點"
    })
    private m_rootNode: Node = null;

    @property({
        type: [Node],
        tooltip: "主遊戲UI"
    })
    private m_mainGameUINodes: Node[] = [];

    @property({
        type: [Node],
        tooltip: "免費遊戲UI"
    })
    private m_freeGameUINodes: Node[] = [];

    @property({
        type: [Node],
        tooltip: "Bonus遊戲UI"
    })
    private m_bonusGameUINodes: Node[] = [];

    @property({
        type: Node,
        tooltip: "黑幕"
    })
    private m_blackMaskNode: Node = null;

    @property({
        type: [SymbolBlackMask],
        tooltip: "符號黑幕"
    })
    private m_symbolBlackMaskNodes: SymbolBlackMask[] = [];


    //#endregion Properties

    //#region Private Variables
    /**@ch 是否已註冊事件 */
    private m_isEventRegistered: boolean = false;

    /**@ch 當前UI類型 */
    private m_currentUIType: UIType = UIType.MainGame;

    /**@ch 快取有效的UI節點 (優化效能)*/
    private m_validMainGameNodes: Node[] = [];
    private m_validFreeGameNodes: Node[] = [];
    private m_validBonusGameNodes: Node[] = [];

    /**@ch 遊戲視窗 */
    private m_gameView: GameView = null;
    //#endregion Private Variables

    //#region Lifecycle Methods
    onLoad() {
        this.ValidateProperties();
        this.CacheValidNodes();
        this.RegisterEvent();
    }

    onDestroy() {
        this.UnregisterEvent();
    }
    //#endregion Lifecycle Methods

    //#region Initialization Methods
    /**
     * @ch 驗證必要屬性
     */
    private ValidateProperties() {
        if (!this.m_rootNode) {
            console.warn('[ReelUIManager] 根節點未設定，部分功能可能無法正常運作');
        }

        if (this.m_mainGameUINodes.length === 0 && this.m_freeGameUINodes.length === 0) {
            console.warn('[ReelUIManager] 未設定任何UI節點');
        }
    }

    /**
     * @ch 快取有效節點 (優化效能)
     */
    private CacheValidNodes() {
        this.m_validMainGameNodes = this.m_mainGameUINodes.filter(Boolean);
        this.m_validFreeGameNodes = this.m_freeGameUINodes.filter(Boolean);
        this.m_validBonusGameNodes = this.m_bonusGameUINodes.filter(Boolean);
    }
    //#endregion Initialization Methods

    //#region Event Management
    /**
     * @ch 註冊事件
     */
    private RegisterEvent() {
        if (this.m_isEventRegistered) {
            return;
        }

        ReelUIManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });

        this.m_isEventRegistered = true;
        this.SetBlackMaskShow(false);
    }

    /**
     * @ch 取消註冊事件
     */
    private UnregisterEvent() {
        if (!this.m_isEventRegistered) {
            return;
        }

        ReelUIManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });

        this.m_isEventRegistered = false;
    }

    /**
     * @ch 事件處理器
     * @param event 事件名稱
     * @param args 參數
     */
    OnEvent(event: string, ...args: any[]) {
        switch (event) {
            case REEL_UI_MANAGER_EVENT.INIT:
                this.m_gameView = args[0];
                break;

            case REEL_UI_MANAGER_EVENT.CHANGE_UI:
                if (this.IsValidUIType(args[0])) {
                    this.ChangeUI(args[0]);
                } else {
                    console.warn('[ReelUIManager] 無效的UI類型:', args[0]);
                }
                break;

            case REEL_UI_MANAGER_EVENT.SHOW:
                this.SetRootNodeShow(true);
                break;

            case REEL_UI_MANAGER_EVENT.HIDE:
                this.SetRootNodeShow(false);
                break;

            case REEL_UI_MANAGER_EVENT.SHOW_BLACK_MASK:
                this.SetBlackMaskShow(true);
                break;

            case REEL_UI_MANAGER_EVENT.HIDE_BLACK_MASK:
                this.SetBlackMaskShow(false);
                break;

            case REEL_UI_MANAGER_EVENT.UPDATE_LOGO:

                break;

            case REEL_UI_MANAGER_EVENT.SET_SYMBOL_BLACK_MASK_SHOW:
                this.SetSymbolBlackMaskShow(args[0], args[1], args[2]);
                break;

            case REEL_UI_MANAGER_EVENT.SET_ALL_SYMBOL_BLACK_MASK_SHOW:
                this.SetAllSymbolBlackMaskShow(args[0], args[1]);
                break;
        }
    }
    //#endregion Event Management

    //#region UI Methods
    /**
     * @ch 更改UI
     * @param type UI類型(0: 主遊戲, 1: 免費遊戲 2:Bonus遊戲)
     */
    private ChangeUI(type: UIType | number) {
        const nextType = this.NormalizeUIType(type);

        // 檢查是否需要切換
        if (nextType === this.m_currentUIType) return;

        // 更新當前狀態
        this.m_currentUIType = nextType;

        // 切換UI
        this.m_rootNode.active = nextType !== UIType.BonusGame;
        this.SetNodesShow(this.m_validMainGameNodes, nextType === UIType.MainGame);
        this.SetNodesShow(this.m_validFreeGameNodes, nextType === UIType.FreeGame);
        this.SetNodesShow(this.m_validBonusGameNodes, nextType === UIType.BonusGame);
    }
    //#endregion UI Methods

    //#region Utility Methods
    /**
     * @ch 驗證UI類型是否有效
     * @param type UI類型
     * @returns 是否有效
     */
    private IsValidUIType(type: any): boolean {
        if (typeof type !== 'number') {
            return false;
        }
        return type >= 0 && type <= 2;
    }

    /**
     * @ch 標準化UI類型
     * @param type UI類型
     * @returns 標準化後的UI類型
     */
    private NormalizeUIType(type: UIType | number): UIType {
        switch (type) {
            case UIType.MainGame:
            case 0:
                return UIType.MainGame;
            case UIType.FreeGame:
            case 1:
                return UIType.FreeGame;
            case UIType.BonusGame:
            case 2:
                return UIType.BonusGame;
            default:
                console.warn(`[ReelUIManager] 未知的UI類型: ${type}，使用預設值 MainGame`);
                return UIType.MainGame;
        }
    }

    /**
     * @ch 設定節點顯示狀態
     * @param node 節點
     * @param isShow 顯示狀態
     */
    private SetNodeShow(node: Node, isShow: boolean) {
        if (node && node.isValid) {
            node.active = isShow;
        }
    }

    /**
     * @ch 設定節點顯示狀態
     * @param nodes 節點陣列
     * @param isShow 顯示狀態
     */
    private SetNodesShow(nodes: Node[], isShow: boolean) {
        nodes.forEach(node => {
            this.SetNodeShow(node, isShow);
        });
    }

    /**
     * @ch 設定根節點顯示狀態
     * @param isShow 顯示狀態
     */
    private SetRootNodeShow(isShow: boolean): void {
        this.SetNodeShow(this.m_rootNode, isShow);
    }

    /**
     * @ch 設定黑幕顯示狀態
     * @param isShow 顯示狀態
     */
    private SetBlackMaskShow(isShow: boolean): void {

        if (isShow) {
            this.ShowAllSymbolBlackMaskByRealPlateInfo();
        } else {
            this.SetAllSymbolBlackMaskShow(false, false);
        }
    }

    /**
     * @ch 設定符號黑幕顯示狀態
     * @param position 位置
     * @param isShow 顯示狀態
     * @param isDark 是否為暗色
     */
    private SetSymbolBlackMaskShow( pos: number, isShow: boolean, isDark: boolean): void {
        if (pos >= 0 && pos < this.m_symbolBlackMaskNodes.length) {
            this.m_symbolBlackMaskNodes[pos].SetBlackMaskShow(
                isShow,
                isDark
                    ? ReelUIManager.SYMBOL_BLACK_MASK_OPACITY_DARK
                    : ReelUIManager.SYMBOL_BLACK_MASK_OPACITY_LIGHT
            );
        }
    }

    /**
     * @ch 設定所有符號黑幕顯示狀態
     * @param isShow 顯示狀態
     * @param isDark 是否為暗色
     */
    private SetAllSymbolBlackMaskShow(isShow: boolean, isDark: boolean): void {
        this.m_symbolBlackMaskNodes.forEach(node => {
            node.SetBlackMaskShow(
                isShow,
                isDark
                    ? ReelUIManager.SYMBOL_BLACK_MASK_OPACITY_DARK
                    : ReelUIManager.SYMBOL_BLACK_MASK_OPACITY_LIGHT
            );
        });
    }

    /**
     * @ch 根據真正盤面資料設定所有符號黑幕顯示狀態
     */
    private ShowAllSymbolBlackMaskByRealPlateInfo(): void {
        for (let col = 0; col < Game_Define.COL; ++col) {
            for (let row = 0; row < Game_Define.ROW; ++row) {
                const symbol = this.m_gameView.SlotReels.GetSymbolInRealPlateInfo(col, row);
                const position = Common.GetPositionFromColRow(col, row);
                const isDark = Game_Define.IsDarkSymbolBlackMask(symbol);

                this.SetSymbolBlackMaskShow(position, true, isDark && !this.m_gameView.IsFreeGame);
            }
        }
    }

    /**
     * @ch 更新Logo圖片
     */

    //#endregion Utility Methods

    //#region 測試功能
    /**
     * @ch 檢查測試按鍵
     */
    private CheckTestKeyCode() {
        if (!DEBUG) return;
        return;
        input.on(Input.EventType.KEY_DOWN, (event: EventKeyboard) => {

            switch (event.keyCode) {

            }
        });
    }
    //#endregion 測試功能
}

