import { _decorator, color, Component, Node, Sprite } from 'cc';
import { setOpacity } from '../Common/NodeProperty';
const { ccclass, property } = _decorator;

@ccclass('SymbolBlackMask')
export class SymbolBlackMask extends Component {
    //#region Properties
    @property( {
        type: Sprite,
        displayName: "黑幕Sprite"
    } )
    private m_blackMaskSprite: Sprite = null;
    //#endregion Properties

    //#region Private Methods
    /**
     * @ch 設定黑幕顯示
     * @param isShow 是否顯示
     * @param opacity 透明度
     */
    SetBlackMaskShow(isShow: boolean, opacity: number) {
        if (this.m_blackMaskSprite) {
            this.m_blackMaskSprite.node.active = isShow;
            setOpacity(this.m_blackMaskSprite.node, opacity);
        }
    }
    //#endregion Private Methods
}

