1	import { _decorator, Component, error, TextAsset, warn } from 'cc';
2	import Game_Define, { SymbolInfo, FeverGameType } from './Game_Define';
3	import { eventManager } from 'db://astarte-framework/Managers';
4	const { ccclass, property } = _decorator;
5	
6	/**@ch 預設隨機符號最大值 */
7	const DEFAULT_RANDOM_SYMBOL_MAX = Game_Define.Symbol.GoldTarget;
8	
9	/**@ch 假轉輪帶資料起始行 */
10	const FAKE_REEL_DATA_START_LINE = 0;
11	
12	/**@ch 假轉輪帶資料行數（從 Game_Define 取得）*/
13	const FAKE_REEL_COUNT = Game_Define.COL;
14	
15	/**@ch 驗證失敗時的預設回傳值 */
16	const DEFAULT_ERROR_VALUES = {
17	    /**@ch 符號預設值 */
18	    SYMBOL: 0,
19	    /**@ch 數字預設值 */
20	    NUMBER: 0,
21	    /**@ch 布林預設值 */
22	    BOOLEAN: false,
23	};
24	
25	/**@ch 假轉輪管理器事件 */
26	export const FAKE_REEL_MANAGER_EVENT = {
27	    /**
28	     * @ch 載入假轉輪帶資料 (MainGame 和 FreeGame)
29	     */
30	    LOAD_FAKE_REEL_DATA: "FAKE_REEL_LOAD_DATA",
31	
32	    /**
33	     * @ch 取得隨機符號
34	     * @param gameType 遊戲類型
35	     * @param reelIndex 轉輪帶編號
36	     * @param position 位置
37	     * @param (選填) callback 完成後的 callback，回傳符號值
38	     */
39	    GET_RANDOM_SYMBOL: "FAKE_REEL_GET_RANDOM_SYMBOL",
40	
41	    /**
42	     * @ch 取得隨機符號資訊
43	     * @param gameType 遊戲類型
44	     * @param reelIndex 轉輪帶編號
45	     * @param position 位置
46	     * @param (選填) callback 完成後的 callback，回傳 SymbolInfo
47	     */
48	    GET_RANDOM_SYMBOL_INFO: "FAKE_REEL_GET_RANDOM_SYMBOL_INFO",
49	
50	    /**
51	     * @ch 取得假轉輪帶資料行數
52	     * @param gameType 遊戲類型
53	     * @param (選填) callback 完成後的 callback，回傳資料行數
54	     */
55	    GET_DATA_LENGTH: "FAKE_REEL_GET_DATA_LENGTH",
56	
57	    /**
58	     * @ch 取得真實假轉輪帶資料行數
59	     * @param gameType 遊戲類型
60	     * @param seed 隨機行數
61	     * @param (選填) callback 完成後的 callback，回傳真實索引
62	     */
63	    GET_REAL_INDEX: "FAKE_REEL_GET_REAL_INDEX",
64	
65	    /**
66	     * @ch 取得假轉輪帶資料隨機行數
67	     * @param gameType 遊戲類型
68	     * @param (選填) callback 完成後的 callback，回傳隨機行數
69	     */
70	    GET_RANDOM_SEED: "FAKE_REEL_GET_RANDOM_SEED",
71	
72	    /**
73	     * @ch 檢查假轉輪帶是否可用
74	     * @param gameType 遊戲類型
75	     * @param (選填) callback 完成後的 callback，回傳是否可用
76	     */
77	    IS_AVAILABLE: "FAKE_REEL_IS_AVAILABLE",
78	};
79	
80	@ccclass('FakeReelManager')
81	export class FakeReelManager extends Component {
82	    //#region Constants
83	    /**
84	     * @ch 需要註冊的事件列表
85	     */
86	    private static readonly EVENTS_TO_REGISTER = [
87	        FAKE_REEL_MANAGER_EVENT.LOAD_FAKE_REEL_DATA,
88	        FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SYMBOL,
89	        FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SYMBOL_INFO,
90	        FAKE_REEL_MANAGER_EVENT.GET_DATA_LENGTH,
91	        FAKE_REEL_MANAGER_EVENT.GET_REAL_INDEX,
92	        FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SEED,
93	        FAKE_REEL_MANAGER_EVENT.IS_AVAILABLE,
94	    ];
95	    //#endregion Constants
96	
97	    //#region Properties
98	    @property({
99	        type: TextAsset,
100	        tooltip: "假轉輪帶資料檔案 - MainGame (FakeReel.txt)"
101	    })
102	    private m_fakeReelAsset_MainGame: TextAsset = null;
103	
104	    @property({
105	        type: TextAsset,
106	        tooltip: "假轉輪帶資料檔案 - FreeGame (FakeReel.txt)"
107	    })
108	    private m_fakeReelAsset_FreeGame: TextAsset = null;
109	    //#endregion Properties
110	
111	    //#region Variables
112	    /**@ch 假轉輪帶資料 [遊戲類型][行][列] */
113	    private m_fakeReelData: { [gameType: number]: number[][] } = {};
114	
115	    /**@ch 假轉輪帶是否已載入 [遊戲類型] */
116	    private m_isFakeReelLoaded: { [gameType: number]: boolean } = {};
117	
118	    /**@ch 是否已經初始化 */
119	    private m_isInitialized: boolean = false;
120	    //#endregion Variables
121	
122	    //#region Lifecycle
123	    /**
124	     * @ch 元件載入時調用
125	     */
126	    onLoad() {
127	        this.RegisterEvent();
128	    }
129	
130	    /**
131	     * @ch 元件銷毀時調用
132	     */
133	    onDestroy() {
134	        if (!this.m_isInitialized) return;
135	        this.UnregisterEvent();
136	        this.m_isInitialized = false;
137	    }
138	    //#endregion Lifecycle
139	
140	    //#region Event Management
141	    /**
142	     * @ch 註冊事件
143	     */
144	    private RegisterEvent() {
145	        FakeReelManager.EVENTS_TO_REGISTER.forEach(eventName => {
146	            eventManager.Register(eventName, this);
147	        });
148	        this.m_isInitialized = true;
149	    }
150	
151	    /**
152	     * @ch 取消註冊事件
153	     */
154	    private UnregisterEvent() {
155	        FakeReelManager.EVENTS_TO_REGISTER.forEach(eventName => {
156	            eventManager.UnRegister(eventName, this);
157	        });
158	    }
159	
160	    /**
161	     * @ch 驗證事件名稱
162	     * @param event 事件名稱
163	     * @returns 是否有效
164	     */
165	    private ValidateEventName(event: string): boolean {
166	        if (!event || typeof event !== 'string') {
167	            warn('[FakeReelManager] OnEvent: 無效的事件名稱', event);
168	            return false;
169	        }
170	        return true;
171	    }
172	
173	    /**
174	     * @ch 驗證遊戲類型參數
175	     * @param args 事件參數
176	     * @returns 遊戲類型（若無效返回 -1）
177	     */
178	    private ValidateGameTypeArg(args: any[]): number {
179	        if (args.length === 0 || typeof args[0] !== 'number') {
180	            warn('[FakeReelManager] 無效的遊戲類型參數', args[0]);
181	            return -1;
182	        }
183	        return args[0];
184	    }
185	
186	    /**
187	     * @ch 驗證轉輪帶編號參數
188	     * @param args 事件參數
189	     * @param startIndex 參數起始索引
190	     * @returns 轉輪帶編號（若無效返回 -1）
191	     */
192	    private ValidateReelIndexArg(args: any[], startIndex: number = 1): number {
193	        if (args.length <= startIndex || typeof args[startIndex] !== 'number') {
194	            warn('[FakeReelManager] 無效的轉輪帶編號參數', args[startIndex]);
195	            return -1;
196	        }
197	        return args[startIndex];
198	    }
199	
200	    /**
201	     * @ch 事件回調
202	     * @param event 事件名稱
203	     * @param args 事件參數
204	     */
205	    OnEvent(event: string, ...args: any[]) {
206	        if (!this.ValidateEventName(event)) {
207	            return;
208	        }
209	
210	        switch (event) {
211	            case FAKE_REEL_MANAGER_EVENT.LOAD_FAKE_REEL_DATA:
212	                this.OnLoadFakeReelData();
213	                break;
214	
215	            case FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SYMBOL:
216	                this.OnGetRandomSymbol(args);
217	                break;
218	
219	            case FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SYMBOL_INFO:
220	                this.OnGetRandomSymbolInfo(args);
221	                break;
222	
223	            case FAKE_REEL_MANAGER_EVENT.GET_DATA_LENGTH:
224	                this.OnGetDataLength(args);
225	                break;
226	
227	            case FAKE_REEL_MANAGER_EVENT.GET_REAL_INDEX:
228	                this.OnGetRealIndex(args);
229	                break;
230	
231	            case FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SEED:
232	                this.OnGetRandomSeed(args);
233	                break;
234	
235	            case FAKE_REEL_MANAGER_EVENT.IS_AVAILABLE:
236	                this.OnIsAvailable(args);
237	                break;
238	
239	            default:
240	                warn('[FakeReelManager] OnEvent: 未知的事件', event);
241	        }
242	    }
243	    //#endregion Event Management
244	
245	    //#region Event Handlers
246	    /**
247	     * @ch 處理 LOAD_FAKE_REEL_DATA 事件
248	     * 載入 MainGame 和 FreeGame 的假轉輪帶資料
249	     */
250	    private OnLoadFakeReelData() {
251	        // 載入 MainGame 資料
252	        this.LoadFakeReelData(FeverGameType.MainGame);
253	
254	        // 載入 FreeGame 資料
255	        this.LoadFakeReelData(FeverGameType.FreeGame);
256	    }
257	
258	    /**
259	     * @ch 處理 GET_RANDOM_SYMBOL 事件
260	     * @param args [gameType, reelIndex, position, callback]
261	     */
262	    private OnGetRandomSymbol(args: any[]) {
263	        const gameType = this.ValidateGameTypeArg(args);
264	        const reelIndex = this.ValidateReelIndexArg(args, 1);
265	        const position = args.length > 2 && typeof args[2] === 'number' ? args[2] : -1;
266	        const callback = args.length > 3 && typeof args[3] === 'function' ? args[3] : null;
267	
268	        // 驗證失敗時執行 callback 並回傳預設值
269	        if (gameType < 0 || reelIndex < 0) {
270	            callback?.(DEFAULT_ERROR_VALUES.SYMBOL);
271	            return;
272	        }
273	
274	        const result = this.GetRandomSymbolFromFakeReel(gameType, reelIndex, position);
275	        callback?.(result);
276	    }
277	
278	    /**
279	     * @ch 處理 GET_RANDOM_SYMBOL_INFO 事件
280	     * @param args [gameType, reelIndex, position, callback]
281	     */
282	    private OnGetRandomSymbolInfo(args: any[]) {
283	        const gameType = this.ValidateGameTypeArg(args);
284	        const reelIndex = this.ValidateReelIndexArg(args, 1);
285	        const position = args.length > 2 && typeof args[2] === 'number' ? args[2] : -1;
286	        const callback = args.length > 3 && typeof args[3] === 'function' ? args[3] : null;
287	
288	        // 驗證失敗時執行 callback 並回傳預設 SymbolInfo
289	        if (gameType < 0 || reelIndex < 0) {
290	            const defaultInfo = new SymbolInfo();
291	            defaultInfo.Symbol = DEFAULT_ERROR_VALUES.SYMBOL;
292	            defaultInfo.Value = DEFAULT_ERROR_VALUES.NUMBER;
293	            defaultInfo.JpType = DEFAULT_ERROR_VALUES.NUMBER;
294	            callback?.(defaultInfo);
295	            return;
296	        }
297	
298	        const result = this.GetRandomSymbolFromFakeReelInfo(gameType, reelIndex, position);
299	        callback?.(result);
300	    }
301	
302	    /**
303	     * @ch 處理 GET_DATA_LENGTH 事件
304	     * @param args [gameType, callback]
305	     */
306	    private OnGetDataLength(args: any[]) {
307	        const gameType = this.ValidateGameTypeArg(args);
308	        const callback = args.length > 1 && typeof args[1] === 'function' ? args[1] : null;
309	
310	        // 驗證失敗時執行 callback 並回傳預設值
311	        if (gameType < 0) {
312	            callback?.(DEFAULT_ERROR_VALUES.NUMBER);
313	            return;
314	        }
315	
316	        const result = this.GetFakeReelDataLength(gameType);
317	        callback?.(result);
318	    }
319	
320	    /**
321	     * @ch 處理 GET_REAL_INDEX 事件
322	     * @param args [gameType, seed, callback]
323	     */
324	    private OnGetRealIndex(args: any[]) {
325	        const gameType = this.ValidateGameTypeArg(args);
326	        const callback = args.length > 2 && typeof args[2] === 'function' ? args[2] : null;
327	
328	        // 驗證 gameType
329	        if (gameType < 0) {
330	            callback?.(DEFAULT_ERROR_VALUES.NUMBER);
331	            return;
332	        }
333	
334	        // 驗證 seed 參數
335	        if (args.length < 2 || typeof args[1] !== 'number') {
336	            warn('[FakeReelManager] 無效的 seed 參數', args[1]);
337	            callback?.(DEFAULT_ERROR_VALUES.NUMBER);
338	            return;
339	        }
340	
341	        const seed = args[1];
342	        const result = this.GetRealFakeReelIndex(gameType, seed);
343	        callback?.(result);
344	    }
345	
346	    /**
347	     * @ch 處理 GET_RANDOM_SEED 事件
348	     * @param args [gameType, callback]
349	     */
350	    private OnGetRandomSeed(args: any[]) {
351	        const gameType = this.ValidateGameTypeArg(args);
352	        const callback = args.length > 1 && typeof args[1] === 'function' ? args[1] : null;
353	
354	        // 驗證失敗時執行 callback 並回傳預設值
355	        if (gameType < 0) {
356	            callback?.(DEFAULT_ERROR_VALUES.NUMBER);
357	            return;
358	        }
359	
360	        const result = this.GetRandomFakeReelSeed(gameType);
361	        callback?.(result);
362	    }
363	
364	    /**
365	     * @ch 處理 IS_AVAILABLE 事件
366	     * @param args [gameType, callback]
367	     */
368	    private OnIsAvailable(args: any[]) {
369	        const gameType = this.ValidateGameTypeArg(args);
370	        const callback = args.length > 1 && typeof args[1] === 'function' ? args[1] : null;
371	
372	        // 驗證失敗時執行 callback 並回傳預設值
373	        if (gameType < 0) {
374	            callback?.(DEFAULT_ERROR_VALUES.BOOLEAN);
375	            return;
376	        }
377	
378	        const result = this.IsFakeReelAvailable(gameType);
379	        callback?.(result);
380	    }
381	    //#endregion Event Handlers
382	
383	    //#region Private Methods
384	    /**@ch 根據遊戲類型取得假轉輪帶資料檔案 */
385	    private GetFakeReelAsset(gameType: number): TextAsset
386	    {
387	        if (gameType === FeverGameType.FreeGame) {
388	            return this.m_fakeReelAsset_FreeGame;
389	        }
390	        // MainGame 為預設值
391	        return this.m_fakeReelAsset_MainGame;
392	    }
393	
394	    /**@ch 載入並解析假轉輪帶資料 */
395	    private LoadFakeReelData(gameType: number): boolean
396	    {
397	        if (this.m_isFakeReelLoaded[gameType]) {
398	            return true;
399	        }
400	
401	        const asset = this.GetFakeReelAsset(gameType);
402	        if (!asset) {
403	            return false;
404	        }
405	
406	        try {
407	            this.ParseFakeReelData(gameType, asset.text);
408	            this.m_isFakeReelLoaded[gameType] = true;
409	            return true;
410	        } catch (err) {
411	            error(`[FakeReelManager] 解析假轉輪帶檔案失敗 (GameType: ${gameType}): ${err}`);
412	            return false;
413	        }
414	    }
415	
416	    /**@ch 解析假轉輪帶檔案內容 */
417	    private ParseFakeReelData(gameType: number, fileContent: string): void
418	    {
419	        const lines = fileContent.split('\n');
420	        this.m_fakeReelData[gameType] = [];
421	
422	        for (let i = FAKE_REEL_DATA_START_LINE; i < lines.length; i++) {
423	            const line = lines[i].trim();
424	            if (line === '') continue;
425	
426	            // 解析每行的格式: "2	10	5	3	5	4	0	5	12	12	8	8	0	2	7"
427	            // 直接用 \t 分割
428	            const parts = line.split('\t');
429	
430	            const symbolData = parts.map(str => {
431	                const num = parseInt(str.trim());
432	                return isNaN(num) ? 0 : num;
433	            });
434	
435	            // 確保每行都有 FAKE_REEL_COUNT 個轉輪帶資料
436	            // log symbolData for debug
437	            // log(`symbolData: ${symbolData}`);
438	            if (symbolData.length === FAKE_REEL_COUNT) {
439	                this.m_fakeReelData[gameType].push(symbolData);
440	            }
441	        }
442	
443	        if (this.m_fakeReelData[gameType].length === 0) {
444	            error(`解析假轉輪帶檔案失敗 (GameType: ${gameType})：沒有找到有效的資料行`);
445	        }
446	    }
447	    //#endregion Private Methods
448	
449	    //#region FakeReel
450	    /**
451	     * @ch 從指定假轉輪帶編號取得隨機符號
452	     * @param gameType 遊戲類型 (MainGame/FreeGame)
453	     * @param reelIndex 轉輪帶編號
454	     * @param position 位置
455	     * @returns 隨機符號
456	     */
457	    private GetRandomSymbolFromFakeReel(gameType: number = FeverGameType.MainGame, reelIndex: number, position: number = -1): number
458	    {
459	        // 確保假轉輪帶資料已載入
460	        if (!this.m_isFakeReelLoaded[gameType]) {
461	            if (!this.LoadFakeReelData(gameType)) {
462	                // 載入失敗，使用預設隨機邏輯
463	                return this.CreateDefaultSymbol();
464	            }
465	        }
466	
467	        // 檢查轉輪帶編號有效性
468	        if (reelIndex < 0 || reelIndex >= FAKE_REEL_COUNT) {
469	            return this.CreateDefaultSymbol();
470	        }
471	
472	        // 檢查是否有資料
473	        if (!this.m_fakeReelData[gameType] || this.m_fakeReelData[gameType].length === 0) {
474	            return this.CreateDefaultSymbol();
475	        }
476	
477	        
478	
479	        // 隨機選擇一個位置
480	        const dataLength = this.m_fakeReelData[gameType].length;
481	        const randomRowIndex = position >= 0 && position < dataLength ? position : Math.floor(Math.random() * dataLength);
482	        const selectedSymbol = this.m_fakeReelData[gameType][randomRowIndex][reelIndex];
483	
484	        return selectedSymbol;
485	    }
486	
487	    /**
488	     * @ch 使用假轉輪帶資料產生隨機符號資訊
489	     * @param gameType 遊戲類型 (MainGame/FreeGame)
490	     * @param reelIndex 轉輪帶編號
491	     * @param position 位置
492	     * @returns 隨機符號資訊
493	     */
494	    private GetRandomSymbolFromFakeReelInfo(gameType: number = FeverGameType.MainGame, reelIndex: number, position: number = -1): SymbolInfo
495	    {
496	        const ret = new SymbolInfo();
497	
498	        try {
499	            ret.Symbol = this.GetRandomSymbolFromFakeReel(gameType, reelIndex, position);
500	            ret.Value = 0;
501	            ret.JpType = 0;
502	        } catch (err) {
503	            ret.Symbol = Math.floor(Math.random() * DEFAULT_RANDOM_SYMBOL_MAX);
504	        }
505	
506	        return ret;
507	    }
508	
509	    /**
510	     * @ch 取得假轉輪帶資料行數
511	     * @param gameType 遊戲類型 (MainGame/FreeGame)
512	     * @returns 假轉輪帶資料行數
513	     */
514	    private GetFakeReelDataLength(gameType: number = FeverGameType.MainGame): number
515	    {
516	        return this.m_fakeReelData[gameType]?.length ?? 0;
517	    }
518	
519	    /**
520	     * @ch 取得真實假轉輪帶資料行數，避免超出範圍
521	     * @param gameType 遊戲類型 (MainGame/FreeGame)
522	     * @param seed 隨機行數
523	     * @returns 假轉輪帶資料行數
524	     */
525	    private GetRealFakeReelIndex(gameType: number = FeverGameType.MainGame, seed: number): number
526	    {
527	        const length = this.m_fakeReelData[gameType]?.length ?? 0;
528	        return length > 0 ? seed % length : 0;
529	    }
530	
531	    /**
532	     * @ch 取得假轉輪帶資料隨機行數
533	     * @param gameType 遊戲類型 (MainGame/FreeGame)
534	     * @returns 隨機假轉輪帶資料行數
535	     */
536	    private GetRandomFakeReelSeed(gameType: number = FeverGameType.MainGame): number
537	    {
538	        const length = this.m_fakeReelData[gameType]?.length ?? 0;
539	        return length > 0 ? Math.floor(Math.random() * length) : 0;
540	    }
541	
542	    /**
543	     * @ch 建立預設隨機符號
544	     * @returns 預設隨機符號
545	     */
546	    private CreateDefaultSymbol(): number
547	    {
548	        return Math.floor(Math.random() * DEFAULT_RANDOM_SYMBOL_MAX);
549	    }
550	
551	    /**
552	     * @ch 檢查假轉輪帶是否可用
553	     * @param gameType 遊戲類型 (MainGame/FreeGame)
554	     * @returns 是否可用
555	     */
556	    private IsFakeReelAvailable(gameType: number = FeverGameType.MainGame): boolean
557	    {
558	        const asset = this.GetFakeReelAsset(gameType);
559	        return asset !== null && (this.m_isFakeReelLoaded[gameType] || this.LoadFakeReelData(gameType));
560	    }
561	    //#endregion FakeReel
562	}
563	
