import { _decorator, Component, error, TextAsset, warn } from 'cc';
import Game_Define, { SymbolInfo, FeverGameType } from './Game_Define';
import { eventManager } from 'db://astarte-framework/Managers';
const { ccclass, property } = _decorator;

/**@ch 預設隨機符號最大值 */
const DEFAULT_RANDOM_SYMBOL_MAX = Game_Define.Symbol.GoldTarget;

/**@ch 假轉輪帶資料起始行 */
const FAKE_REEL_DATA_START_LINE = 0;

/**@ch 假轉輪帶資料行數（從 Game_Define 取得）*/
const FAKE_REEL_COUNT = Game_Define.COL;

/**@ch 驗證失敗時的預設回傳值 */
const DEFAULT_ERROR_VALUES = {
    /**@ch 符號預設值 */
    SYMBOL: 0,
    /**@ch 數字預設值 */
    NUMBER: 0,
    /**@ch 布林預設值 */
    BOOLEAN: false,
};

/**@ch 假轉輪管理器事件 */
export const FAKE_REEL_MANAGER_EVENT = {
    /**
     * @ch 載入假轉輪帶資料 (MainGame 和 FreeGame)
     */
    LOAD_FAKE_REEL_DATA: "FAKE_REEL_LOAD_DATA",

    /**
     * @ch 取得隨機符號
     * @param gameType 遊戲類型
     * @param reelIndex 轉輪帶編號
     * @param position 位置
     * @param (選填) callback 完成後的 callback，回傳符號值
     */
    GET_RANDOM_SYMBOL: "FAKE_REEL_GET_RANDOM_SYMBOL",

    /**
     * @ch 取得隨機符號資訊
     * @param gameType 遊戲類型
     * @param reelIndex 轉輪帶編號
     * @param position 位置
     * @param (選填) callback 完成後的 callback，回傳 SymbolInfo
     */
    GET_RANDOM_SYMBOL_INFO: "FAKE_REEL_GET_RANDOM_SYMBOL_INFO",

    /**
     * @ch 取得假轉輪帶資料行數
     * @param gameType 遊戲類型
     * @param (選填) callback 完成後的 callback，回傳資料行數
     */
    GET_DATA_LENGTH: "FAKE_REEL_GET_DATA_LENGTH",

    /**
     * @ch 取得真實假轉輪帶資料行數
     * @param gameType 遊戲類型
     * @param seed 隨機行數
     * @param (選填) callback 完成後的 callback，回傳真實索引
     */
    GET_REAL_INDEX: "FAKE_REEL_GET_REAL_INDEX",

    /**
     * @ch 取得假轉輪帶資料隨機行數
     * @param gameType 遊戲類型
     * @param (選填) callback 完成後的 callback，回傳隨機行數
     */
    GET_RANDOM_SEED: "FAKE_REEL_GET_RANDOM_SEED",

    /**
     * @ch 檢查假轉輪帶是否可用
     * @param gameType 遊戲類型
     * @param (選填) callback 完成後的 callback，回傳是否可用
     */
    IS_AVAILABLE: "FAKE_REEL_IS_AVAILABLE",
};

@ccclass('FakeReelManager')
export class FakeReelManager extends Component {
    //#region Constants
    /**
     * @ch 需要註冊的事件列表
     */
    private static readonly EVENTS_TO_REGISTER = [
        FAKE_REEL_MANAGER_EVENT.LOAD_FAKE_REEL_DATA,
        FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SYMBOL,
        FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SYMBOL_INFO,
        FAKE_REEL_MANAGER_EVENT.GET_DATA_LENGTH,
        FAKE_REEL_MANAGER_EVENT.GET_REAL_INDEX,
        FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SEED,
        FAKE_REEL_MANAGER_EVENT.IS_AVAILABLE,
    ];
    //#endregion Constants

    //#region Properties
    @property({
        type: TextAsset,
        tooltip: "假轉輪帶資料檔案 - MainGame (FakeReel.txt)"
    })
    private m_fakeReelAsset_MainGame: TextAsset = null;

    @property({
        type: TextAsset,
        tooltip: "假轉輪帶資料檔案 - FreeGame (FakeReel.txt)"
    })
    private m_fakeReelAsset_FreeGame: TextAsset = null;
    //#endregion Properties

    //#region Variables
    /**@ch 假轉輪帶資料 [遊戲類型][行][列] */
    private m_fakeReelData: { [gameType: number]: number[][] } = {};

    /**@ch 假轉輪帶是否已載入 [遊戲類型] */
    private m_isFakeReelLoaded: { [gameType: number]: boolean } = {};

    /**@ch 是否已經初始化 */
    private m_isInitialized: boolean = false;
    //#endregion Variables

    //#region Lifecycle
    /**
     * @ch 元件載入時調用
     */
    onLoad() {
        this.RegisterEvent();
    }

    /**
     * @ch 元件銷毀時調用
     */
    onDestroy() {
        if (!this.m_isInitialized) return;
        this.UnregisterEvent();
        this.m_isInitialized = false;
    }
    //#endregion Lifecycle

    //#region Event Management
    /**
     * @ch 註冊事件
     */
    private RegisterEvent() {
        FakeReelManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });
        this.m_isInitialized = true;
    }

    /**
     * @ch 取消註冊事件
     */
    private UnregisterEvent() {
        FakeReelManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });
    }

    /**
     * @ch 驗證事件名稱
     * @param event 事件名稱
     * @returns 是否有效
     */
    private ValidateEventName(event: string): boolean {
        if (!event || typeof event !== 'string') {
            warn('[FakeReelManager] OnEvent: 無效的事件名稱', event);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證遊戲類型參數
     * @param args 事件參數
     * @returns 遊戲類型（若無效返回 -1）
     */
    private ValidateGameTypeArg(args: any[]): number {
        if (args.length === 0 || typeof args[0] !== 'number') {
            warn('[FakeReelManager] 無效的遊戲類型參數', args[0]);
            return -1;
        }
        return args[0];
    }

    /**
     * @ch 驗證轉輪帶編號參數
     * @param args 事件參數
     * @param startIndex 參數起始索引
     * @returns 轉輪帶編號（若無效返回 -1）
     */
    private ValidateReelIndexArg(args: any[], startIndex: number = 1): number {
        if (args.length <= startIndex || typeof args[startIndex] !== 'number') {
            warn('[FakeReelManager] 無效的轉輪帶編號參數', args[startIndex]);
            return -1;
        }
        return args[startIndex];
    }

    /**
     * @ch 事件回調
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent(event: string, ...args: any[]) {
        if (!this.ValidateEventName(event)) {
            return;
        }

        switch (event) {
            case FAKE_REEL_MANAGER_EVENT.LOAD_FAKE_REEL_DATA:
                this.OnLoadFakeReelData();
                break;

            case FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SYMBOL:
                this.OnGetRandomSymbol(args);
                break;

            case FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SYMBOL_INFO:
                this.OnGetRandomSymbolInfo(args);
                break;

            case FAKE_REEL_MANAGER_EVENT.GET_DATA_LENGTH:
                this.OnGetDataLength(args);
                break;

            case FAKE_REEL_MANAGER_EVENT.GET_REAL_INDEX:
                this.OnGetRealIndex(args);
                break;

            case FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SEED:
                this.OnGetRandomSeed(args);
                break;

            case FAKE_REEL_MANAGER_EVENT.IS_AVAILABLE:
                this.OnIsAvailable(args);
                break;

            default:
                warn('[FakeReelManager] OnEvent: 未知的事件', event);
        }
    }
    //#endregion Event Management

    //#region Event Handlers
    /**
     * @ch 處理 LOAD_FAKE_REEL_DATA 事件
     * 載入 MainGame 和 FreeGame 的假轉輪帶資料
     */
    private OnLoadFakeReelData() {
        // 載入 MainGame 資料
        this.LoadFakeReelData(FeverGameType.MainGame);

        // 載入 FreeGame 資料
        this.LoadFakeReelData(FeverGameType.FreeGame);
    }

    /**
     * @ch 處理 GET_RANDOM_SYMBOL 事件
     * @param args [gameType, reelIndex, position, callback]
     */
    private OnGetRandomSymbol(args: any[]) {
        const gameType = this.ValidateGameTypeArg(args);
        const reelIndex = this.ValidateReelIndexArg(args, 1);
        const position = args.length > 2 && typeof args[2] === 'number' ? args[2] : -1;
        const callback = args.length > 3 && typeof args[3] === 'function' ? args[3] : null;

        // 驗證失敗時執行 callback 並回傳預設值
        if (gameType < 0 || reelIndex < 0) {
            callback?.(DEFAULT_ERROR_VALUES.SYMBOL);
            return;
        }

        const result = this.GetRandomSymbolFromFakeReel(gameType, reelIndex, position);
        callback?.(result);
    }

    /**
     * @ch 處理 GET_RANDOM_SYMBOL_INFO 事件
     * @param args [gameType, reelIndex, position, callback]
     */
    private OnGetRandomSymbolInfo(args: any[]) {
        const gameType = this.ValidateGameTypeArg(args);
        const reelIndex = this.ValidateReelIndexArg(args, 1);
        const position = args.length > 2 && typeof args[2] === 'number' ? args[2] : -1;
        const callback = args.length > 3 && typeof args[3] === 'function' ? args[3] : null;

        // 驗證失敗時執行 callback 並回傳預設 SymbolInfo
        if (gameType < 0 || reelIndex < 0) {
            const defaultInfo = new SymbolInfo();
            defaultInfo.Symbol = DEFAULT_ERROR_VALUES.SYMBOL;
            defaultInfo.Value = DEFAULT_ERROR_VALUES.NUMBER;
            defaultInfo.JpType = DEFAULT_ERROR_VALUES.NUMBER;
            callback?.(defaultInfo);
            return;
        }

        const result = this.GetRandomSymbolFromFakeReelInfo(gameType, reelIndex, position);
        callback?.(result);
    }

    /**
     * @ch 處理 GET_DATA_LENGTH 事件
     * @param args [gameType, callback]
     */
    private OnGetDataLength(args: any[]) {
        const gameType = this.ValidateGameTypeArg(args);
        const callback = args.length > 1 && typeof args[1] === 'function' ? args[1] : null;

        // 驗證失敗時執行 callback 並回傳預設值
        if (gameType < 0) {
            callback?.(DEFAULT_ERROR_VALUES.NUMBER);
            return;
        }

        const result = this.GetFakeReelDataLength(gameType);
        callback?.(result);
    }

    /**
     * @ch 處理 GET_REAL_INDEX 事件
     * @param args [gameType, seed, callback]
     */
    private OnGetRealIndex(args: any[]) {
        const gameType = this.ValidateGameTypeArg(args);
        const callback = args.length > 2 && typeof args[2] === 'function' ? args[2] : null;

        // 驗證 gameType
        if (gameType < 0) {
            callback?.(DEFAULT_ERROR_VALUES.NUMBER);
            return;
        }

        // 驗證 seed 參數
        if (args.length < 2 || typeof args[1] !== 'number') {
            warn('[FakeReelManager] 無效的 seed 參數', args[1]);
            callback?.(DEFAULT_ERROR_VALUES.NUMBER);
            return;
        }

        const seed = args[1];
        const result = this.GetRealFakeReelIndex(gameType, seed);
        callback?.(result);
    }

    /**
     * @ch 處理 GET_RANDOM_SEED 事件
     * @param args [gameType, callback]
     */
    private OnGetRandomSeed(args: any[]) {
        const gameType = this.ValidateGameTypeArg(args);
        const callback = args.length > 1 && typeof args[1] === 'function' ? args[1] : null;

        // 驗證失敗時執行 callback 並回傳預設值
        if (gameType < 0) {
            callback?.(DEFAULT_ERROR_VALUES.NUMBER);
            return;
        }

        const result = this.GetRandomFakeReelSeed(gameType);
        callback?.(result);
    }

    /**
     * @ch 處理 IS_AVAILABLE 事件
     * @param args [gameType, callback]
     */
    private OnIsAvailable(args: any[]) {
        const gameType = this.ValidateGameTypeArg(args);
        const callback = args.length > 1 && typeof args[1] === 'function' ? args[1] : null;

        // 驗證失敗時執行 callback 並回傳預設值
        if (gameType < 0) {
            callback?.(DEFAULT_ERROR_VALUES.BOOLEAN);
            return;
        }

        const result = this.IsFakeReelAvailable(gameType);
        callback?.(result);
    }
    //#endregion Event Handlers

    //#region Private Methods
    /**@ch 根據遊戲類型取得假轉輪帶資料檔案 */
    private GetFakeReelAsset(gameType: number): TextAsset
    {
        if (gameType === FeverGameType.FreeGame) {
            return this.m_fakeReelAsset_FreeGame;
        }
        // MainGame 為預設值
        return this.m_fakeReelAsset_MainGame;
    }

    /**@ch 載入並解析假轉輪帶資料 */
    private LoadFakeReelData(gameType: number): boolean
    {
        if (this.m_isFakeReelLoaded[gameType]) {
            return true;
        }

        const asset = this.GetFakeReelAsset(gameType);
        if (!asset) {
            return false;
        }

        try {
            this.ParseFakeReelData(gameType, asset.text);
            this.m_isFakeReelLoaded[gameType] = true;
            return true;
        } catch (err) {
            error(`[FakeReelManager] 解析假轉輪帶檔案失敗 (GameType: ${gameType}): ${err}`);
            return false;
        }
    }

    /**@ch 解析假轉輪帶檔案內容 */
    private ParseFakeReelData(gameType: number, fileContent: string): void
    {
        const lines = fileContent.split('\n');
        this.m_fakeReelData[gameType] = [];

        for (let i = FAKE_REEL_DATA_START_LINE; i < lines.length; i++) {
            const line = lines[i].trim();
            if (line === '') continue;

            // 解析每行的格式: "2	10	5	3	5	4	0	5	12	12	8	8	0	2	7"
            // 直接用 \t 分割
            const parts = line.split('\t');

            const symbolData = parts.map(str => {
                const num = parseInt(str.trim());
                return isNaN(num) ? 0 : num;
            });

            // 確保每行都有 FAKE_REEL_COUNT 個轉輪帶資料
            // log symbolData for debug
            // log(`symbolData: ${symbolData}`);
            if (symbolData.length === FAKE_REEL_COUNT) {
                this.m_fakeReelData[gameType].push(symbolData);
            }
        }

        if (this.m_fakeReelData[gameType].length === 0) {
            error(`解析假轉輪帶檔案失敗 (GameType: ${gameType})：沒有找到有效的資料行`);
        }
    }
    //#endregion Private Methods

    //#region FakeReel
    /**
     * @ch 從指定假轉輪帶編號取得隨機符號
     * @param gameType 遊戲類型 (MainGame/FreeGame)
     * @param reelIndex 轉輪帶編號
     * @param position 位置
     * @returns 隨機符號
     */
    private GetRandomSymbolFromFakeReel(gameType: number = FeverGameType.MainGame, reelIndex: number, position: number = -1): number
    {
        // 確保假轉輪帶資料已載入
        if (!this.m_isFakeReelLoaded[gameType]) {
            if (!this.LoadFakeReelData(gameType)) {
                // 載入失敗，使用預設隨機邏輯
                return this.CreateDefaultSymbol();
            }
        }

        // 檢查轉輪帶編號有效性
        if (reelIndex < 0 || reelIndex >= FAKE_REEL_COUNT) {
            return this.CreateDefaultSymbol();
        }

        // 檢查是否有資料
        if (!this.m_fakeReelData[gameType] || this.m_fakeReelData[gameType].length === 0) {
            return this.CreateDefaultSymbol();
        }



        // 隨機選擇一個位置
        const dataLength = this.m_fakeReelData[gameType].length;
        const randomRowIndex = position >= 0 && position < dataLength ? position : Math.floor(Math.random() * dataLength);
        const selectedSymbol = this.m_fakeReelData[gameType][randomRowIndex][reelIndex];

        return selectedSymbol;
    }

    /**
     * @ch 使用假轉輪帶資料產生隨機符號資訊
     * @param gameType 遊戲類型 (MainGame/FreeGame)
     * @param reelIndex 轉輪帶編號
     * @param position 位置
     * @returns 隨機符號資訊
     */
    private GetRandomSymbolFromFakeReelInfo(gameType: number = FeverGameType.MainGame, reelIndex: number, position: number = -1): SymbolInfo
    {
        const ret = new SymbolInfo();

        try {
            ret.Symbol = this.GetRandomSymbolFromFakeReel(gameType, reelIndex, position);
            ret.Value = 0;
            ret.JpType = 0;
        } catch (err) {
            ret.Symbol = Math.floor(Math.random() * DEFAULT_RANDOM_SYMBOL_MAX);
        }

        return ret;
    }

    /**
     * @ch 取得假轉輪帶資料行數
     * @param gameType 遊戲類型 (MainGame/FreeGame)
     * @returns 假轉輪帶資料行數
     */
    private GetFakeReelDataLength(gameType: number = FeverGameType.MainGame): number
    {
        return this.m_fakeReelData[gameType]?.length ?? 0;
    }

    /**
     * @ch 取得真實假轉輪帶資料行數，避免超出範圍
     * @param gameType 遊戲類型 (MainGame/FreeGame)
     * @param seed 隨機行數
     * @returns 假轉輪帶資料行數
     */
    private GetRealFakeReelIndex(gameType: number = FeverGameType.MainGame, seed: number): number
    {
        const length = this.m_fakeReelData[gameType]?.length ?? 0;
        return length > 0 ? seed % length : 0;
    }

    /**
     * @ch 取得假轉輪帶資料隨機行數
     * @param gameType 遊戲類型 (MainGame/FreeGame)
     * @returns 隨機假轉輪帶資料行數
     */
    private GetRandomFakeReelSeed(gameType: number = FeverGameType.MainGame): number
    {
        const length = this.m_fakeReelData[gameType]?.length ?? 0;
        return length > 0 ? Math.floor(Math.random() * length) : 0;
    }

    /**
     * @ch 建立預設隨機符號
     * @returns 預設隨機符號
     */
    private CreateDefaultSymbol(): number
    {
        return Math.floor(Math.random() * DEFAULT_RANDOM_SYMBOL_MAX);
    }

    /**
     * @ch 檢查假轉輪帶是否可用
     * @param gameType 遊戲類型 (MainGame/FreeGame)
     * @returns 是否可用
     */
    private IsFakeReelAvailable(gameType: number = FeverGameType.MainGame): boolean
    {
        const asset = this.GetFakeReelAsset(gameType);
        return asset !== null && (this.m_isFakeReelLoaded[gameType] || this.LoadFakeReelData(gameType));
    }
    //#endregion FakeReel
}

