/**@ch 轉輪滾動方向 */
enum ReelDirection
{
    Down = -1,
    Up = 1,
}

/**@ch 彈性轉輪配置介面 */
interface ColumnConfig {
    targetSymbolCount: number;    // 目標符號數量
    visibleSymbolCount: number;   // 可視符號數量
}

interface ReelModeConfig {
    columns: ColumnConfig[];
    replacementTiming: number;     // 符號替換時機（剩餘圈數）
    fakeSymbolStrategy: string;   // 假符號生成策略
}

let HARD_STOP_INTERVAL_TIME = 0.15;
