let BOUNCE_UP_TIME = 0.05; // 回彈時間(上) tools.divide( 3, 60 );
let BOUNCE_DOWN_TIME = 0.0333; // 回彈時間(下) tools.divide( 2, 60 );
let BOUNCE_DISTANCE = 12; // 回彈距離

/**@ch 轉輪系統彈性配置 */
class ReelSystemConfig {
    // 基礎配置
    static readonly DEFAULT_CONFIG = {
        // 一般遊戲配置
        normal: {
            columns: [
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第1列
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第2列
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第3列
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第4列
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第5列
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第6列
            ],
            replacementTiming: 1.0, // 剩餘1圈替換
            fakeSymbolStrategy: 'random' // 隨機假符號
        },

        // 免費遊戲配置（預留）
        freeGame: {
            columns: [
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第1列
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第2列
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第3列
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第4列
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第5列
                { targetSymbolCount: 5, visibleSymbolCount: 5 }, // 第6列
            ],
            replacementTiming: 1.0,
            fakeSymbolStrategy: 'random'
        }
    };

    // 當前使用的配置
    private currentConfig: ReelModeConfig = ReelSystemConfig.DEFAULT_CONFIG.normal;

    // 切換配置
    SwitchToMode(mode: 'normal' | 'freeGame') {
        this.currentConfig = ReelSystemConfig.DEFAULT_CONFIG[mode];
    }

    // 取得列配置
    GetColumnConfig(columnIndex: number): ColumnConfig {
        return this.currentConfig.columns[columnIndex] || { targetSymbolCount: 5, visibleSymbolCount: 4 };
    }

    // 取得替換時機
    GetReplacementTiming(): number {
        return this.currentConfig.replacementTiming;
    }

    // 取得假符號策略
    GetFakeSymbolStrategy(): string {
        return this.currentConfig.fakeSymbolStrategy;
    }
}

