781	    /**@ch 設定初始盤面 */
782	    CreateSymbol()
783	    {
784	        // plate = 0 下，plate = 1 中，plate = 2 上
785	        for ( let plate = 0; plate < SHOW_COLUMNS; ++plate )
786	        {
787	            let arr = new Array<ColumnSymbol>;
788	            this.m_allColumns.push( arr );
789	        }
790	
791	        // 因為圖層要下壓上，所以從上往下建盤面
792	        for ( let plate = SHOW_COLUMNS - 1; plate >= 0; --plate )
793	        {
794	            this.CreatePlate( plate );
795	        }
796	        
797	
798	        this.m_isLoadingComplete = true;
799	    }
800	
801	    /**
802	     * @ch 設定一個 ( COL X N ) 盤面 (N 由彈性轉輪系統修正)
803	     * @param plate 盤面索引 (0 ~ SHOW_COLUMNS-1)
804	     */
805	    CreatePlate( plate: number )
806	    {
807	        for ( let col = 0; col < Game_Define.COL; ++col )
808	        {
809	            let colName = col.toString();
810	            let nodeName = Game_Define.NODE_PREFIX_NAME[ plate ] + colName;
811	            // 根據實際符號數量創建 ColumnSymbol 由彈性轉輪系統修正
812	            let rowCount = this.GetTargetSymbolCount( col );
813	            const parentNode = this.m_reelMask;
814	            let columnSymbol = new ColumnSymbol( parentNode, this.m_gameView, nodeName, rowCount );
815	            columnSymbol.Name = nodeName;
816	
817	            // 設定位置(需等InitValue後才能使用)
818	            columnSymbol.SetPosition( v3( this.m_reelXPos[ col ], this.GetReelYPos( col, plate ) ) );
819	            
820	            let symbols = new Array<number>();
821	            let add = col;
822	            for ( let row = 0; row < rowCount; ++row )
823	            {
824	                // 上下露出片 col 0 用 M5 避免 M1 太大凸出
825	                const useSmall = col === 0 && plate !== Game_Define.MIDDLE_PLATE_INDEX;
826	                symbols.push( useSmall ? Game_Define.Symbol.M5 : Game_Define.Symbol.M1 + add );
827	            }
828	            let symbolInfos = this.ConvertSymbolsToSymbolInfos( symbols );
829	            columnSymbol.SetSymbolInfos( symbolInfos );
830	
831	            if ( plate === Game_Define.MIDDLE_PLATE_INDEX )
832	            {
833	                const visibleSymbolCount = this.GetVisibleSymbolCount( col );
834	                const columnData = symbols.slice( 0, visibleSymbolCount );
835	
836	                this.m_plateInfo.push( RecoverSpinAck.getInstance().ConvertColumns( columnData ) );
837	
838	                // 創建中間符號的空Node
839	                for ( let i = 0; i < visibleSymbolCount; ++i )
840	                {
841	                    let middleSymbolEmptyNode = new Node();
842	                    middleSymbolEmptyNode.name = "Middle_" + col.toString() + i.toString();
843	                    middleSymbolEmptyNode.layer = Define.Layer2D;
844	                    parentNode.addChild(middleSymbolEmptyNode);
845	                    const symbolNode = columnSymbol.GetSymbolNodeAt( i );
846	                    middleSymbolEmptyNode.setPosition(symbolNode.position);
847	                    this.m_middleSymbolEmptyNodes.push(middleSymbolEmptyNode);
848	                }
849	            }
850	            this.m_allColumns[ plate ].push( columnSymbol );
851	        }
852	    }
