864	    /**@ch 開始Spin，處理相關設置 */
865	    StartSpin()
866	    {
867	        // 關鍵：每次 Spin 都必須重置時間相關狀態，否則第二次會沿用上一局 StopTime/m_time 導致直接停輪
868	        this.m_time = 0;
869	        this.StopTime = 0;
870	        this.m_isStop = false;
871	        // 修 R-1：StartSpin 即凍結轉輪（恢復舊版首幀凍結），凍結貫穿整個掉落序列，
872	        // 預告期間空盤面（舊盤已掉出）保持靜止；drop-in 原子解除才設回 false。
873	        this.m_isInDropMode = true;
874	        // 清掉上一局可能殘留的動畫 handle（如 MgOmen 未消費），確保本局 TriggerDropOut 冪等鍵以 null 起點、
875	        // 能正常建立本局的掉落動畫（INV-3 兜底，防 stale promise 污染下一局）。
876	        this.m_dropAllSymbolsOutOfScreenPromise = null;
877	        this.m_isClickStopBtn = false;
878	        this.m_isPlayStopSound = [ false, false, false, false, false, false ];
879	        this.m_isPlayStopEffect = [ false, false, false, false, false, false ];
880	        this.m_isHasScatterNearWin = false;
881	        this.m_scatterNearWinReachedMax = false;
882	
883	        // 強制關閉上一局殘留的 NearWin 特效
884	        if (this.m_scatterNearWinColumn > -1) {
885	            this.m_scatterNearWinColumn = -1;
886	            this.StopNearWinSound();
887	            this.SetSymbolDark(false, -1);
888	        }
889	        this.m_gameView.EffectPlate.StopNearWin();
890	
891	        // 恢復上一局隱藏的 Scatter symbol
892	        for (const pos of this.m_hiddenScatterPositions) {
893	            this.SetSymbolShow(pos.col, pos.row, true);
894	        }
895	        this.m_hiddenScatterPositions = [];
896	        this.m_gameView.EffectPlate.ReturnAllScatterEnterAnimationNodes();
897	
898	        // 防禦性清除：確保所有 symbol 的 sprite 子節點是 active 的 + 移除殘留 reparented 節點
899	        for (let col = 0; col < Game_Define.COL; col++) {
900	            const vc = this.GetVisibleSymbolCount(col);
901	            for (let row = 0; row < vc; row++) {
902	                const cell = this.GetSymbolSingleCellFromColRow(col, row);
903	                if (!cell) continue;
904	                const children = cell.ThisNode.children;
905	                for (let i = children.length - 1; i >= 0; i--) {
906	                    const child = children[i];
907	                    if (child['_reparented']) {
908	                        child.removeFromParent();
909	                        child.active = false;
910	                        delete child['_reparented'];
911	                        delete child['_origParent'];
912	                    }
913	                }
914	                if (children[0]) children[0].active = true;
915	            }
916	        }
917	
918	        // 恢復所有符號的圖層順序
919	        this.ResetAllSymbolLayers();
920	
921	        // 重要：重置每輪的停輪時間，等待 server 回來再由 SetReelTimes() 設定
922	        for ( let i = 0; i < Game_Define.COL; ++i )
923	        {
924	            this.m_reelStopTime[ i ] = this.m_reelPreTime[ i ] = null;
925	            this.m_nearWinSpeedUp[ i ] = 1;
926	        }
927	
928	        // 重置所有符號切換狀態（但保留鎖定狀態）
929	        for ( let col = 0; col < this.m_isChangeToFinalSymbol.length; ++col )
930	        {
931	            // 只重置未鎖定的轉輪
932	            if ( !this.m_lockColumn[ col ] )
933	            {
934	                this.m_isChangeToFinalSymbol[ col ] = false;
935	            }
936	        }
937	
938	        // 清空並重新初始化有效的列索引（只對中輪帶）
939	        this.m_isNotChangeSymbolThisRound = {};
940	        for ( let col = 0; col < Game_Define.COL; ++col )
941	        {
942	            this.m_isNotChangeSymbolThisRound[ col ] = true;
943	        }
944	
945	        // 初始化上下輪帶狀態
946	        this.m_upDownReelChangeState = {};
947	        for ( let plate = 0; plate < SHOW_COLUMNS; ++plate )
948	        {
949	            for ( let col = 0; col < Game_Define.COL; ++col )
950	            {
951	                const nodeName = Game_Define.NODE_PREFIX_NAME[ plate ] + col.toString();
952	                if ( plate !== Game_Define.MIDDLE_PLATE_INDEX ) // 只處理上下輪帶
953	                {
954	                    this.m_upDownReelChangeState[ nodeName ] = true;
955	                }
956	            }
957	        }
958	
959	        // 設定假轉輪帶隨機行數位置
960	
961	        // 掉落模式：「按 Spin（spin 開始）即觸發舊盤面掉出」——在此 StartSpin 末端觸發，
962	        // 使舊盤掉出與等待伺服器 ack 的空檔重疊（手感即時）。預告與新盤進場改在資料到位後，
963	        // 由各 path（一般遊戲=OnRecvSpinAck、FG=SpinState）先 WaitDropOutComplete() 等掉完再做。
964	        this.TriggerDropOut();
965	    }
