967	    /**
968	     * @ch 觸發「舊盤面掉出畫面」（由 StartSpin 末端在「按 Spin（spin 開始）」時點呼叫）
969	     * @description INV-1：同步成對設定凍結旗標 + 建立動畫 promise，無中間 await。
970	     *              INV-4：對「已在 drop mode」為 no-op（冪等），防止同一局重複觸發建立孤兒 promise。
971	     */
972	    public TriggerDropOut(): void {
973	        // INV-4 冪等：冪等鍵改判「動畫 handle 是否已建立」（非凍結旗標 m_isInDropMode）。
974	        // 因 m_isInDropMode 自 StartSpin 起即為 true（凍結），不能再當冪等鍵，否則 promise 永不建立（FP-1）。
975	        if (this.m_dropAllSymbolsOutOfScreenPromise) {
976	            return;
977	        }
978	        // 舊盤掉出即 spin 起手 = 新一局（新 RoundInfo；cascade 不走此路徑）→ 讓懸賞令與舊盤同步早退場。
979	        // 放在冪等 return 之後，確保同局只發一次；退場為 fire-and-forget，稍後 SetNowRoundInfo 的
980	        // RebuildAll 因 item 已退場（active=false）只跑新的 PlayIn（不重複 PlayOut）。
981	        eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.PLAY_OUT_ALL);
982	        // INV-1 設定綁定：確保凍結中（StartSpin 已設 true，此處冪等再確認）並建立掉落動畫 handle。
983	        this.m_isInDropMode = true;
984	        this.m_dropAllSymbolsOutOfScreenPromise = this.DropAllSymbolsOutOfScreen();
985	    }
986	
987	    /**
