onLoad()
{
    // 轉輪節奏模組：三幣瑞龍
    let tempoSettingCb = () =>
    {
        let tempoModule = tempoSetting?.TempoSetting.TripleCoinTreasure;
        if ( !tempoModule )
        {
            return;
        }
        this.m_riseTime = tempoModule.BASE.RISE_TIME;
        this.m_upLength = tempoModule.BASE.UP_LENGTH;
        this.m_spinBufferTime01 = tempoModule.BASE.SPIN_BUFFER_TIME_01;
        this.m_spinBufferTime02 = tempoModule.BASE.SPIN_BUFFER_TIME_02;
        this.m_downLength = tempoModule.BASE.DOWN_LENGTH;

        this.m_timesOfBaseSpin = tempoModule.BASE.TIMES_OF_BASE_SPIN;
        this.m_spinIntervalTimes = tempoModule.BASE.SPIN_INTERVAL_TIMES;
        this.m_spinDelayTime = tempoModule.BASE.SPIN_DELAY_TIME;
    };
    tempoSettingCb();
    tempoSetting?.AddCb( tempoSettingCb );

    this.CheckTestKeyCode();
}

/**
 * @ch 初始化
 * @param gameView 遊戲視窗
 */
Init( gameView: GameView )
{
    this.m_gameView = gameView;
    this.InitValue();
}

/**@ch 設定初始盤面 */
CreateSymbol()
{
    // plate = 0 下，plate = 1 中，plate = 2 上
    for ( let plate = 0; plate < SHOW_COLUMNS; ++plate )
    {
        let arr = new Array<ColumnSymbol>;
        this.m_allColumns.push( arr );
    }

    // 因為圖層要下壓上，所以從上往下建盤面
    for ( let plate = SHOW_COLUMNS - 1; plate >= 0; --plate )
    {
        this.CreatePlate( plate );
    }


    this.m_isLoadingComplete = true;
}

/**
 * @ch 設定一個 ( COL X N ) 盤面 (N 由彈性轉輪系統修正)
 * @param plate 盤面索引 (0 ~ SHOW_COLUMNS-1)
 */
CreatePlate( plate: number )
{
    for ( let col = 0; col < Game_Define.COL; ++col )
    {
        let colName = col.toString();
        let nodeName = Game_Define.NODE_PREFIX_NAME[ plate ] + colName;
        // 根據實際符號數量創建 ColumnSymbol 由彈性轉輪系統修正
        let rowCount = this.GetTargetSymbolCount( col );
        const parentNode = this.m_reelMask;
        let columnSymbol = new ColumnSymbol( parentNode, this.m_gameView, nodeName, rowCount );
        columnSymbol.Name = nodeName;

        // 設定位置(需等InitValue後才能使用)
        columnSymbol.SetPosition( v3( this.m_reelXPos[ col ], this.GetReelYPos( col, plate ) ) );

        let symbols = new Array<number>();
        let add = col;
        for ( let row = 0; row < rowCount; ++row )
        {
            // 上下露出片 col 0 用 M5 避免 M1 太大凸出
            const useSmall = col === 0 && plate !== Game_Define.MIDDLE_PLATE_INDEX;
            symbols.push( useSmall ? Game_Define.Symbol.M5 : Game_Define.Symbol.M1 + add );
        }
        let symbolInfos = this.ConvertSymbolsToSymbolInfos( symbols );
        columnSymbol.SetSymbolInfos( symbolInfos );

        if ( plate === Game_Define.MIDDLE_PLATE_INDEX )
        {
            const visibleSymbolCount = this.GetVisibleSymbolCount( col );
            const columnData = symbols.slice( 0, visibleSymbolCount );

            this.m_plateInfo.push( RecoverSpinAck.getInstance().ConvertColumns( columnData ) );

            // 創建中間符號的空Node
            for ( let i = 0; i < visibleSymbolCount; ++i )
            {
                let middleSymbolEmptyNode = new Node();
                middleSymbolEmptyNode.name = "Middle_" + col.toString() + i.toString();
                middleSymbolEmptyNode.layer = Define.Layer2D;
                parentNode.addChild(middleSymbolEmptyNode);
                const symbolNode = columnSymbol.GetSymbolNodeAt( i );
                middleSymbolEmptyNode.setPosition(symbolNode.position);
                this.m_middleSymbolEmptyNodes.push(middleSymbolEmptyNode);
            }
        }
        this.m_allColumns[ plate ].push( columnSymbol );
    }
}

/**
 * @ch 產生隨機symbol
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @returns 隨機符號
 */
RandomSymbol(col: number)
{
    return this.GetFakeReelRandomSymbol(col, true);
}

/**@ch 開始Spin，處理相關設置 */
StartSpin()
{
    // 關鍵：每次 Spin 都必須重置時間相關狀態，否則第二次會沿用上一局 StopTime/m_time 導致直接停輪
    this.m_time = 0;
    this.StopTime = 0;
    this.m_isStop = false;
    // 修 R-1：StartSpin 即凍結轉輪（恢復舊版首幀凍結），凍結貫穿整個掉落序列，
    // 預告期間空盤面（舊盤已掉出）保持靜止；drop-in 原子解除才設回 false。
    this.m_isInDropMode = true;
    // 清掉上一局可能殘留的動畫 handle（如 MgOmen 未消費），確保本局 TriggerDropOut 冪等鍵以 null 起點、
    // 能正常建立本局的掉落動畫（INV-3 兜底，防 stale promise 污染下一局）。
    this.m_dropAllSymbolsOutOfScreenPromise = null;
    this.m_isClickStopBtn = false;
    this.m_isPlayStopSound = [ false, false, false, false, false, false ];
    this.m_isPlayStopEffect = [ false, false, false, false, false, false ];
    this.m_isHasScatterNearWin = false;
    this.m_scatterNearWinReachedMax = false;

    // 強制關閉上一局殘留的 NearWin 特效
    if (this.m_scatterNearWinColumn > -1) {
        this.m_scatterNearWinColumn = -1;
        this.StopNearWinSound();
        this.SetSymbolDark(false, -1);
    }
    this.m_gameView.EffectPlate.StopNearWin();

    // 恢復上一局隱藏的 Scatter symbol
    for (const pos of this.m_hiddenScatterPositions) {
        this.SetSymbolShow(pos.col, pos.row, true);
    }
    this.m_hiddenScatterPositions = [];
    this.m_gameView.EffectPlate.ReturnAllScatterEnterAnimationNodes();

    // 防禦性清除：確保所有 symbol 的 sprite 子節點是 active 的 + 移除殘留 reparented 節點
    for (let col = 0; col < Game_Define.COL; col++) {
        const vc = this.GetVisibleSymbolCount(col);
        for (let row = 0; row < vc; row++) {
            const cell = this.GetSymbolSingleCellFromColRow(col, row);
            if (!cell) continue;
            const children = cell.ThisNode.children;
            for (let i = children.length - 1; i >= 0; i--) {
                const child = children[i];
                if (child['_reparented']) {
                    child.removeFromParent();
                    child.active = false;
                    delete child['_reparented'];
                    delete child['_origParent'];
                }
            }
            if (children[0]) children[0].active = true;
        }
    }

    // 恢復所有符號的圖層順序
    this.ResetAllSymbolLayers();

    // 重要：重置每輪的停輪時間，等待 server 回來再由 SetReelTimes() 設定
    for ( let i = 0; i < Game_Define.COL; ++i )
    {
        this.m_reelStopTime[ i ] = this.m_reelPreTime[ i ] = null;
        this.m_nearWinSpeedUp[ i ] = 1;
    }

    // 重置所有符號切換狀態（但保留鎖定狀態）
    for ( let col = 0; col < this.m_isChangeToFinalSymbol.length; ++col )
    {
        // 只重置未鎖定的轉輪
        if ( !this.m_lockColumn[ col ] )
        {
            this.m_isChangeToFinalSymbol[ col ] = false;
        }
    }

    // 清空並重新初始化有效的列索引（只對中輪帶）
    this.m_isNotChangeSymbolThisRound = {};
    for ( let col = 0; col < Game_Define.COL; ++col )
    {
        this.m_isNotChangeSymbolThisRound[ col ] = true;
    }

    // 初始化上下輪帶狀態
    this.m_upDownReelChangeState = {};
    for ( let plate = 0; plate < SHOW_COLUMNS; ++plate )
    {
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            const nodeName = Game_Define.NODE_PREFIX_NAME[ plate ] + col.toString();
            if ( plate !== Game_Define.MIDDLE_PLATE_INDEX ) // 只處理上下輪帶
            {
                this.m_upDownReelChangeState[ nodeName ] = true;
            }
        }
    }

    // 設定假轉輪帶隨機行數位置

    // 掉落模式：「按 Spin（spin 開始）即觸發舊盤面掉出」——在此 StartSpin 末端觸發，
    // 使舊盤掉出與等待伺服器 ack 的空檔重疊（手感即時）。預告與新盤進場改在資料到位後，
    // 由各 path（一般遊戲=OnRecvSpinAck、FG=SpinState）先 WaitDropOutComplete() 等掉完再做。
    this.TriggerDropOut();
}

/**
 * @ch 觸發「舊盤面掉出畫面」（由 StartSpin 末端在「按 Spin（spin 開始）」時點呼叫）
 * @description INV-1：同步成對設定凍結旗標 + 建立動畫 promise，無中間 await。
 *              INV-4：對「已在 drop mode」為 no-op（冪等），防止同一局重複觸發建立孤兒 promise。
 */
public TriggerDropOut(): void {
    // INV-4 冪等：冪等鍵改判「動畫 handle 是否已建立」（非凍結旗標 m_isInDropMode）。
    // 因 m_isInDropMode 自 StartSpin 起即為 true（凍結），不能再當冪等鍵，否則 promise 永不建立（FP-1）。
    if (this.m_dropAllSymbolsOutOfScreenPromise) {
        return;
    }
    // 舊盤掉出即 spin 起手 = 新一局（新 RoundInfo；cascade 不走此路徑）→ 讓懸賞令與舊盤同步早退場。
    // 放在冪等 return 之後，確保同局只發一次；退場為 fire-and-forget，稍後 SetNowRoundInfo 的
    // RebuildAll 因 item 已退場（active=false）只跑新的 PlayIn（不重複 PlayOut）。
    eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.PLAY_OUT_ALL);
    // INV-1 設定綁定：確保凍結中（StartSpin 已設 true，此處冪等再確認）並建立掉落動畫 handle。
    this.m_isInDropMode = true;
    this.m_dropAllSymbolsOutOfScreenPromise = this.DropAllSymbolsOutOfScreen();
}

/**
 * @ch 等待「舊盤面掉出畫面」完成。
 * @description 掉出已在 StartSpin（按 Spin 時）觸發，此處供「預告 / 新盤進場」前等掉完。
 *              ack 快於掉出動畫 → 等剩餘；慢於 → 已 resolved，瞬間通過。promise 由 drop-in 消費後清 null，
 *              本方法在 drop-in 之前呼叫，promise 仍非 null。
 */
public async WaitDropOutComplete(): Promise<void> {
    if (this.m_dropAllSymbolsOutOfScreenPromise) {
        await this.m_dropAllSymbolsOutOfScreenPromise;
    }
}

/**
 * @ch 將所有輪帶的 Symbol 往下掉落出畫面
 * @description 主要用於等待 server 回盤面前先清空畫面，避免舊盤面殘留。
 *              以「一個一個依序掉落」的方式播放，且總耗時約 1.5 秒。
 */
private async DropAllSymbolsOutOfScreen(): Promise<void> {
    if (!this.m_viewSize || !this.m_symbolSize || !this.m_allColumns || this.m_allColumns.length === 0) {
        return;
    }

    const totalDuration = 1.5;
    const singleFallDuration = Math.min(0.4, totalDuration);

    // 收集所有要掉落的 Node，並依指定順序排列：
    // 「第一列(col=0) 先全部掉完（從最後一顆開始）→ 再輪到第二列(col=1) → ...」
    // 也就是 col：左→右，row：下→上（同一列先掉完才換下一列）。
    const symbolNodes: Node[] = [];
    const middlePlateIndex = Game_Define.MIDDLE_PLATE_INDEX;

    // 只處理中間盤面（掉落模式只有一個盤面）
    const plateColumns = this.m_allColumns[middlePlateIndex];
    if (plateColumns) {
        for (let col = 0; col < Game_Define.COL; col++) {
            const columnSymbol = plateColumns[col];
            if (!columnSymbol) {
                continue;
            }

            const nodeCount = columnSymbol.NodeCount ?? 0;
            for (let row = nodeCount - 1; row >= 0; row--) {
                const singleCell = columnSymbol.GetSingleCell(row);
                const symbolNode = singleCell?.GetNode?.() ?? singleCell?.ThisNode ?? null;
                if (symbolNode && symbolNode.isValid) {
                    symbolNodes.push(symbolNode);
                }
            }
        }
    }

    if (symbolNodes.length === 0) {
        return;
    }

    const fallDistance = this.m_viewSize.height + this.m_symbolSize.height;
    const stagger = 0; // 全部一起掉出盤面

