    await Promise.all(promises);

    // 動畫結束後，直接隱藏所有輪帶的 Symbol
    for (let plate = 0; plate < SHOW_COLUMNS; plate++) {
        const plateColumns = this.m_allColumns[plate];
        if (!plateColumns) continue;

        for (let col = 0; col < Game_Define.COL; col++) {
            const columnSymbol = plateColumns[col];
            columnSymbol?.SetColumnShow?.(false);
        }
    }
}

/**
 * @ch 停輪相關表演
 * @param isFast 是否快速停輪
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 */
private ShowStopSymbolEffect(isFast: boolean, col: number) {
    if (this.m_isPlayStopEffect[col]) {
        return;
    }

    this.m_isPlayStopEffect[col] = true;
    log(`[Target DEBUG] ShowStopSymbolEffect col=${col}, plateInfo symbols=${this.m_plateInfo?.[col]?.Col}`);

    // 檢查該列是否會出現Scatter，如果會則播放Scatter動畫
    if (SCATTER_COLUMNS.includes(col)) {
        // 該列有 Scatter 時播 Stop 動畫
        if (this.HasScatterInColumn(col)) {
            this.PlayColumnScattersAnimation(col, false);
        }

        // 檢查Scatter預中獎
        if (this.HasScatterInColumn(col)) {
            const scatterInCol = this.CountScattersInColumn(col);
            this.m_scatterCollectCount += scatterInCol;
            log(`[NearWin DEBUG] OnColumnStop col=${col}: scatterInCol=${scatterInCol}, total=${this.m_scatterCollectCount}, isHasNearWin=${this.m_isHasScatterNearWin}`);

            // 視覺上累計到足夠 Scatter 時啟動 NearWin（FG 及已觸發進 FG 條件時不觸發；本局已達上限後不再重開）
            if (this.m_scatterCollectCount >= SCATTER_NEARWIN_COLLECT_COUNT && this.m_scatterCollectCount < SCATTER_NEARWIN_MAX_COUNT && !this.m_gameView.IsFreeGame && !this.m_scatterNearWinReachedMax) {
                this.m_isHasScatterNearWin = true;

                // 前面已停下的 scatter 播 Enter（排除本列，本列由 Stop 完成後自動接）
                for (const pos of this.m_hiddenScatterPositions) {
                    if (pos.col !== col) {
                        this.m_gameView.EffectPlate.PlayScatterEnterAnimation(pos.col, pos.row, true);
                    }
                }

                const nextColumn = col + 1;
                if (nextColumn < Game_Define.COL) {
                    this.ShowScatterPreWinAnimation(nextColumn);
                }
            } else if (this.m_scatterCollectCount >= SCATTER_NEARWIN_MAX_COUNT && this.m_isHasScatterNearWin) {
                log(`[NearWin DEBUG] MAX REACHED at col=${col}: count=${this.m_scatterCollectCount}, MAX=${SCATTER_NEARWIN_MAX_COUNT}, closing NearWin`);
                this.m_isHasScatterNearWin = false;
                this.StopNearWinSound();
                this.m_gameView.EffectPlate.StopNearWin();
                this.m_gameView.EffectPlate.FreezeAllScattersToStop(); // 達上限：場上 scatter 切回 Stop 並凍結最後一格（不 loop、不還原普通符號）
                this.m_scatterNearWinReachedMax = true; // 本局已達上限，後續天降不再重新觸發 NearWin
            }
        }
    }

    // 隱藏Scatter預中獎動畫（只在未觸發 NearWin 時關閉）
    if (!this.m_isHasScatterNearWin && col >= SCATTER_NEARWIN_ANIMATION_COLUMN && this.m_scatterNearWinColumn > -1) {
        this.HideScatterPreWinAnimation(this.m_scatterNearWinColumn);
    }

    // 該列停輪時關掉該列的 NearWin 光效，若 NearWin 已觸發則移到下一列
    if (col >= 0 && col < this.m_gameView.EffectPlate.NearWinEffectsCount) {
        this.m_gameView.EffectPlate.StopNearWinAt(col);
        // NearWin 已觸發、該列沒有新 Scatter（有的話上面已處理）、還有後續列 → 光效移到下一列
        if (this.m_isHasScatterNearWin && !this.HasScatterInColumn(col)) {
            const nextCol = col + 1;
            if (nextCol < Game_Define.COL) {
                this.ShowScatterPreWinAnimation(nextCol);
            }
        }
    }

    // 標靶停輪：播音效 + Stop→Idle 動畫
    this.PlayColumnTargetsStopEffect(col);

    // Scatter 停輪音效
    this.PlayColumnScattersStopEffect(col);
}

/**
 * @ch 標靶停輪：播音效 + Stop→Idle
 */
private PlayColumnTargetsStopEffect(col: number) {
    for (let row = 0; row < Game_Define.ROW; row++) {
        const symbol = this.GetSymbolInRealPlateInfo(col, row);
        if (symbol === Game_Define.Symbol.Target || symbol === Game_Define.Symbol.GoldTarget) {
            log(`[Target] StopEffect col=${col} row=${row} symbol=${symbol}`);
            this.m_gameView.EffectPlate.ReelStopEffect(col, row, symbol, null);
        }
    }
}

