/**
 * @ch 旋轉
 * @param dt 時間
 */
Spin( dt )
{
    this.m_time = this.ToolsStrip( this.m_time + dt );
    if ( this.IsStop )
    {
        return;
    }

    // 掉落模式：不跑轉輪帶，等 DropSymbolsToBoardByServerPlateInfo 設 m_isStop
    // 凍結來源改為 m_isInDropMode（promise 已降格為純動畫 handle）。L1268 IsStop 不動。
    if ( this.m_isInDropMode || this.m_isStop ) {
        return;
    }

    this.SpinAll( dt, NORMAL_COLUMNS );

    if ( this.StopTime === 0 || this.m_time <= this.StopTime )
    {
        return;
    }

    this.CheckPlateInfo();
    // 全部停輪時，停止 NearWin 特效和 Scatter 動畫
    if (!this.m_isStop) {
        // 同步關閉 NearWin 光效
        this.m_gameView.EffectPlate.StopNearWin();
        this.StopNearWinSound();
        this.m_scatterNearWinColumn = -1;
        // 解暗
        this.SetSymbolDark(false, -1);
        eventManager.Dispatch("REEL_UI_MANAGER_SET_ALL_SYMBOL_BLACK_MASK_SHOW", false, false);

        // 恢復隱藏的 Scatter symbol

        for (const pos of this.m_hiddenScatterPositions) {
            this.SetSymbolShow(pos.col, pos.row, true);
        }
        this.m_hiddenScatterPositions = [];
        this.m_gameView.EffectPlate.ReturnAllScatterEnterAnimationNodes();
    }

    // 該停輪了
    this.m_isStop = true;
}

/**
 * @ch 旋轉上、中、下所有輪帶，第二個參數為控制單輪
 * @param dt 時間
 * @param cols 列索引 (0 ~ Game_Define.COL-1)
 */
SpinAll( dt, cols: number[] )
{
    for ( let col = 0; col < cols.length; ++col )
    {
        const actualCol = cols[ col ];

        // 檢查轉輪是否被鎖定
        if ( this.m_lockColumn[ actualCol ] )
        {
            continue; // 跳過鎖定的轉輪
        }

        // NearWin 觸發後才加速
        let isNearWin = false;
        let spinTime = this.CalSpinTime( actualCol, isNearWin );

        // 計算時間
        let curTime = this.m_time;
        let riseTime = this.m_riseTime * Game_Define.COL;
        let moveLength = ( ( ( curTime - riseTime ) % spinTime ) / spinTime ) * this.GetTotalLength( actualCol );

        // NearWin 觸發後加速：直接放大移動量
        if (this.m_isHasScatterNearWin && this.m_nearWinSpeedUp[actualCol] > 1) {
            moveLength *= this.m_nearWinSpeedUp[actualCol];
            moveLength = moveLength % this.GetTotalLength( actualCol );
        }

        // 上中下總共三條
        for ( let plate = 0; plate < SHOW_COLUMNS; ++plate )
        {
            this.Spin_RealSpinMultiple( actualCol, this.m_allColumns[ plate ][ actualCol ], plate, moveLength );
        }
    }
}

/**
 * @ch 根據時間，做出對應表演，座標與一般直角座標系相同
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param target 列符號
 * @param upMiddleLow 上中下輪帶
 * @param moveLength 移動長度
 */
Spin_RealSpinMultiple( col: number, target: ColumnSymbol, upMiddleLow: number, moveLength: number )
{
    const curTime = this.m_time;
    const reelStopTime = this.m_reelStopTime[ col ];

    const riseTime = this.m_riseTime * Game_Define.COL;

    let x = this.m_reelXPos[ col ];
    let y = this.GetReelYPos( col, upMiddleLow );
    const directionMultiplier = this.GetDirectionMultiplier();

    if (
        upMiddleLow === Game_Define.MIDDLE_PLATE_INDEX
        && curTime > reelStopTime + riseTime + this.m_spinBufferTime01 + this.m_spinBufferTime02
    )
    {
        y = this.GetReelYPos( col, upMiddleLow );
        this.m_tempVec3.set( x, y, 0 );
        target.SetPosition( this.m_tempVec3 );
    }

    if ( curTime < this.m_riseTime * col ) // 抬起續力表演
    {
        return;
    }
    else if ( curTime < this.m_riseTime * ( col + 1 ) )
    {
        let moveLength = ( ( curTime - this.m_riseTime * col ) / this.m_riseTime ) * this.m_upLength;
        this.m_tempVec3.set( x, y + moveLength, 0 );
        target.SetPosition( this.m_tempVec3 );
    }
    else if ( curTime < riseTime )
    {
        this.m_tempVec3.set( x, y + this.m_upLength, 0 );
        target.SetPosition( this.m_tempVec3 );
    }
    else if ( reelStopTime === null || curTime < reelStopTime + riseTime ) // 轉動表演
    {
        let finalMoveLength = this.CheckMoveLength( moveLength, this.GetComparePos( col, upMiddleLow ), col, target );
        this.m_tempVec3.set( x, y + directionMultiplier * finalMoveLength, 0 );
        target.SetPosition( this.m_tempVec3 );
    }
    else if ( curTime < reelStopTime + riseTime + this.m_spinBufferTime01 ) // 準備要停了
    {
        let moveLength = ( ( curTime - reelStopTime - riseTime ) / this.m_spinBufferTime01 ) * this.m_downLength;
        this.m_tempVec3.set( x, y + directionMultiplier * moveLength, 0 );
        target.SetPosition( this.m_tempVec3 );

        // 只在第一次進入停輪階段時設定最終符號
        if ( upMiddleLow === Game_Define.MIDDLE_PLATE_INDEX )
        {
            this.CheckChangeToFinalSymbol( col, target, true );
        }
        this.CheckPlayStopSoundAndEffect( col );
    }
    else if ( curTime < reelStopTime + riseTime + this.m_spinBufferTime01 + this.m_spinBufferTime02 )
    {
        let moveLength = ( ( curTime - reelStopTime - riseTime - this.m_spinBufferTime01 ) / this.m_spinBufferTime02 ) * this.m_downLength;
        const settleOffset = this.m_downLength - moveLength;
        this.m_tempVec3.set( x, y + directionMultiplier * settleOffset, 0 );
        target.SetPosition( this.m_tempVec3 );

        // 只在第一次進入停輪階段時設定最終符號
        if ( upMiddleLow === Game_Define.MIDDLE_PLATE_INDEX )
        {
            this.CheckChangeToFinalSymbol( col, target, false );
        }
    }
    else
    {
        // 最終停輪位置
        y = this.GetReelYPos( col, upMiddleLow );
        this.m_tempVec3.set( x, y, 0 );
        target.SetPosition( this.m_tempVec3 );

        // 只在第一次進入停輪階段時設定最終符號
        if ( upMiddleLow === Game_Define.MIDDLE_PLATE_INDEX )
        {
            this.CheckChangeToFinalSymbol( col, target, true );
        }

        this.CheckPlayStopSoundAndEffect( col );
        this.ShowStopSymbolEffect( this.m_isClickStopBtn, col );
    }
}

/**
 * @ch 確認是不是可以換Symbol了，順便拉到上面
 * @param moveLength 移動長度
 * @param comapreLength 比較長度
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param target 列符號
 * @returns 移動長度
 */
CheckMoveLength( moveLength: number, comapreLength: number, col: number, target: ColumnSymbol )
{
    // 如果不是中輪帶，使用類似的邏輯但獨立的狀態追蹤
    if ( !target.Name || isNaN(Number(target.Name)) ) 
    {
        if ( moveLength < comapreLength )
        {
            return moveLength;
        }

        // 使用輪帶名稱作為狀態追蹤的鍵值
        const stateKey = target.Name;

        if (
            this.m_upDownReelChangeState[ stateKey ] !== false
            && moveLength - comapreLength < this.m_viewSize.height
        ) 
        {
            this.ChangeSymbol( col, target, this.m_isClickStopBtn );
            this.m_upDownReelChangeState[ stateKey ] = false;
        }
        else if ( moveLength - comapreLength >= this.m_viewSize.height )
        {
            // 移動超過視窗高度，重置為可換符號狀態
            this.m_upDownReelChangeState[ stateKey ] = true;
        }

        return moveLength - this.GetTotalLength( col );
    }

    // 只有中輪帶執行原本的切換邏輯
    let index = Number( target.Name ); // 這裡index就是列號 (0,1,2,3,4,5)

    if ( moveLength < comapreLength )
    {
        return moveLength;
    }

    if (
        this.m_isNotChangeSymbolThisRound[ index ]
        && moveLength - comapreLength < this.m_viewSize.height
    ) // 可以換了
    {
        this.ChangeSymbol( col, target, this.m_isClickStopBtn );
        this.m_isNotChangeSymbolThisRound[ index ] = false;
    }
    else if ( moveLength - comapreLength >= this.m_viewSize.height )
    {
        // 移動超過視窗高度，重置為可換符號狀態
        this.m_isNotChangeSymbolThisRound[ index ] = true;
    }
    // 其他情況保持現有狀態不變
    return moveLength - this.GetTotalLength( col );
}

/**
 * @ch 幫單個column換Symbol
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param columnSymbol 列符號
 * @param isStop 是否停輪
 */
ChangeSymbol( col: number, columnSymbol: ColumnSymbol, isStop: boolean )
{
    let index = Number( columnSymbol.Name );
    let reelPreTime = this.m_reelPreTime[ col ];
    let riseTime = this.m_riseTime * this.m_viewSize.height * SHOW_COLUMNS;
    let nearWin = this.m_isHasScatterNearWin; // NearWin 觸發後加速
    let isFakeReel = false; // 是否假輪帶

    if ( isStop )
    {
        // 停輪階段
        if ( !isNaN( index ) )
        {
            // 中間輪帶 - 使用伺服器提供的最終盤面（包含假符號）
            if ( this.m_plateInfoWithFakeSymbol && this.m_plateInfoWithFakeSymbol[ col ] && this.m_plateInfoWithFakeSymbol[ col ].Col )
            {
                // 從 CColumn 中提取 SymbolInfo 陣列
                const symbolInfos = this.ConvertSymbolsToSymbolInfos( this.m_plateInfoWithFakeSymbol[ col ].Col );
                columnSymbol.SetSymbolInfos( symbolInfos );
            }
            else
            {
                isFakeReel = true;
            }
        }
        else
        {
            // 上下輪帶 - 使用隨機符號
            isFakeReel = true;
        }
    }
    else
    {
        let spinTime = this.CalSpinTime( col, nearWin );

        if ( !isNaN( index )
            && ( ( reelPreTime !== null && this.m_time >= reelPreTime )
                || ( Math.abs( this.m_time - ( reelPreTime + riseTime ) ) < spinTime ) )
        )
        {
            // 中間輪帶準備停輪階段 - 使用伺服器提供的最終盤面（包含假符號）
            if ( this.m_plateInfoWithFakeSymbol && this.m_plateInfoWithFakeSymbol[ col ] && this.m_plateInfoWithFakeSymbol[ col ].Col )
            {
                // 從 CColumn 中提取 SymbolInfo 陣列
                const symbolInfos = this.ConvertSymbolsToSymbolInfos( this.m_plateInfoWithFakeSymbol[ col ].Col );
                columnSymbol.SetSymbolInfos( symbolInfos );
            }
            else
            {
                isFakeReel = true;
            }
        }
        else
        {
            // 旋轉中或上下輪帶 - 使用隨機符號
            isFakeReel = true;
        }
    }

    if ( isFakeReel )
    {
        this.SetColumnSymbolForFakeReel( col, columnSymbol );
    }
}

/**
 * @ch 強制更換符號 (用於表演)
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param row 行索引 (0 ~ Game_Define.ROW-1)
 * @param symbolId 符號ID
 */
ForceChangeSymbol(col: number, row: number, symbolId: number) {
    const column = this.GetColumn(col);
    if (!column) {
        return;
    }

    column.SetSymbolAt(row, symbolId);

    // 更新盤面資料
    if (this.m_plateInfo && this.m_plateInfo[col]) {
        this.m_plateInfo[col].Col[row] = symbolId;
    }

    // 更新假輪帶資料
    if (this.m_plateInfoWithFakeSymbol && this.m_plateInfoWithFakeSymbol[col]) {
        this.m_plateInfoWithFakeSymbol[col].Col[row] = symbolId;
    }

    // 如果切換成需要調整圖層的符號，調整該符號的圖層
    if (this.IsNeedAdjustSymbol(symbolId)) {
        this.AdjustSingleSymbolLayer(col, row);
    }
}

/**
 * @ch 強制更換符號 (用於表演)
 * @param symbolPosition 位置
 * @param symbolId 符號ID
 */
ForceChangeSymbolByPosition(symbolPosition: number, symbolId: number) {
    const { col, row } = this.GetColRowFromPosition(symbolPosition);
    this.ForceChangeSymbol(col, row, symbolId);
}

/**@ch 取得盤面資料指定位置的符號 */
GetSymbolInPlateInfoByPosition( symbolPosition: number ) : number
{
    const { col, row } = this.GetColRowFromPosition(symbolPosition);
    return this.GetSymbolInPlateInfo(col, row);
}

/**@ch 取得盤面資料指定位置的符號 */
GetSymbolInPlateInfo( col: number, row: number ) : number
{
    if (this.m_plateInfoWithFakeSymbol[col]) {
        return this.m_plateInfoWithFakeSymbol[ col ].Col[ row ];
    }
    return 0;
}

