/**
 * @ch 根據是不是FG來判斷要怎麼隨機產生symbol
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @returns 符號
 */
CheckIsFreeGameAndGetSymbols(col: number): number[] {
    let symbols: number[] = [];
    let symbolNumber = this.GetTargetSymbolCount(col); // 根據列獲取行數
    for (let i = 0; i < symbolNumber; ++i) {
        if (this.m_reelDirection === ReelDirection.Up) {
            symbols.push(this.RandomSymbol(col));
        } else {
            symbols.unshift(this.RandomSymbol(col));
        }
    }
    return symbols;
}

/**
 * @ch 最後一道防線 - 確保最終符號只設定一次
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param node 列符號
 * @param isStop 是否停輪
 */
CheckChangeToFinalSymbol(col: number, node: ColumnSymbol, isStop = false) {
    if (!this.m_isChangeToFinalSymbol[col]) {
        this.m_isChangeToFinalSymbol[col] = true;

        // 在換成最終符號前調整圖層（停輪前一圈）
        this.AdjustSymbolsLayerByColumn(col);

        this.ChangeSymbol(col, node, isStop);
    }
}

/**
 * @ch 確認停輪效果(亞瑟王音效與動態分開)
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 */
CheckPlayStopSoundAndEffect(col: number) {
    if (!this.m_isPlayStopSound[col]) {
        this.m_isPlayStopSound[col] = true;
        if (this.m_isClickStopBtn) {
            this.m_isPlayStopSound = [true, true, true, true, true, true];
        }
        this.PlayReelSound();
    }
}

/**
 * @ch 設置當局盤面資料，並設置停輪時間
 * @param content 當局盤面資料
 */
SetPlateInfo(content: protocol.ar2pq9Proto.IPlateInfo) {
    // error("This Plate is ", content);

    this.m_plateInfo = RecoverSpinAck.getInstance().ConvertPlate(content.PlateSymbol);

    this.m_featurePosQueue = Common.ParseFeaturePosQueue(content.FeaturePosQueue);

    // 直接處理並保留完整的資料結構，避免多次轉換導致的資料失真
    this.m_plateInfoWithFakeSymbol = this.PreprocessPlateDataForServer(this.m_plateInfo);

    if (!this.m_gameView.IsMgOmen) {
        // 掉落模式：新盤面從上方掉入
        this.DropSymbolsToBoardByServerPlateInfo();
    }
}

/**
 * @ch 從 server 盤面資料（已預處理）取得指定位置的符號 ID
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param row 行索引 (0 ~ visibleSymbolCount-1)
 * @returns 符號ID，無效時回傳 null
 */
private GetSymbolIdFromServerPlateInfo(col: number, row: number): number | null {
    if (col < 0 || col >= Game_Define.COL || row < 0) {
        return null;
    }

    const visibleSymbolCount = this.GetVisibleSymbolCount(col);
    if (row >= visibleSymbolCount) {
        return null;
    }

    const symbolId = this.m_plateInfoWithFakeSymbol?.[col]?.Col?.[row];
    if (typeof symbolId !== "number" || isNaN(symbolId)) {
        return null;
    }

    return symbolId;
}

/**
