private async StartFallSymbol(
    delayTime: number,
    col: number,
    row: number,
    count: number,
    symbolId: number,
    moveDuration: number = Game_Define.SYMBOL_FALL_DURATION
): Promise<void> {
    const symbolNode = this.GetSymbolNodeFromColRow(col, row);
    if (!symbolNode) {
        warn(`[SlotReel.StartFallSymbol] Symbol node not found at [col:${col}, row:${row}]`);
        return;
    }

    // 驗證參數
    if (count < 0) {
        warn(`[SlotReel.StartFallSymbol] Invalid count parameter: ${count}`);
        return;
    }

    if (symbolId < 0 || symbolId >= Game_Define.Symbol.MAX) {
        warn(`[SlotReel.StartFallSymbol] Invalid symbolId parameter: ${symbolId}, valid range: [0, ${Game_Define.Symbol.MAX})`);
        return;
    }

    // 顯示Symbol
    this.SetSymbolShow(col, row, true);

    // 位置計算優化：緩存位置，避免重複調用getPosition()
    const targetPos = symbolNode.getPosition();
    const offset = count * Game_Define.SymbolHeight;
    const startPos = v3(targetPos.x, targetPos.y + offset, targetPos.z);

    // 設定初始位置（落下起點）
    symbolNode.setPosition(startPos);

    // 切換Symbol
    this.ForceChangeSymbol(col, row, symbolId);

    await Define.Wait(this, delayTime);

    // 使用 tween 移動 Symbol 到目標位置（跟天降一樣的掉落速度）
    const duration = SYMBOL_ENTER_MOVE_TIME * count / Game_Define.ROW;
    await new Promise<void>(resolve => {
        const isSpecialSymbol = symbolId === Game_Define.Symbol.Scatter || symbolId === Game_Define.Symbol.SilverScatter || symbolId === Game_Define.Symbol.GoldScatter || symbolId === Game_Define.Symbol.Target || symbolId === Game_Define.Symbol.GoldTarget;
        const t = tween(symbolNode)
            .to(duration, { position: targetPos }, { easing: 'sineIn' })
            .call(() => {
                // 播放Symbol掉落音效
                AudioManager.Play(AudioManager.AudioClips.Symbol_Drop);
                // NearWin 模式下只有 Scatter 落地才震動
                const isScatter = symbolId === Game_Define.Symbol.Scatter || symbolId === Game_Define.Symbol.SilverScatter || symbolId === Game_Define.Symbol.GoldScatter;
                if (this.m_isHasScatterNearWin && isScatter) {
                    this.m_gameView.BigHintShake(0.3, Game_Define.NEAR_WIN_SHAKE_DISTANCE);
                }
            });
        if (!isSpecialSymbol) {
            t.by(BOUNCE_UP_TIME, { position: v3(0, 6) })
             .by(BOUNCE_DOWN_TIME, { position: v3(0, -6) });
        }
        t.call(() => {
                symbolNode.setPosition(targetPos);
                resolve();
            })
            .start();
    });
}

/**
 * @ch 開始落下所有Symbol
 * @param eliminatePositions 被消掉的Symbol位置
 * @param plateInfo 新盤面資料
 * @param delayTime 延遲時間
 */
async StartFallAllSymbols(eliminatePositions: number[], plateInfo: protocol.ar2pq9Proto.IPlateInfo, delayTime: number) {

    await Define.Wait( this, delayTime );

    // 提取所有要掉落的Column，並建立對應的序號
    const columnsToFall = new Set<number>();
    for (const pos of eliminatePositions) {
        const { col } = this.GetColRowFromPosition(pos);
        columnsToFall.add(col);
    }
    // 排序後建立 col → columnIndex 的對應
    const sortedColumns = Array.from(columnsToFall).sort((a, b) => a - b);
    const columnIndexMap = new Map<number, number>();
    sortedColumns.forEach((col, index) => {
        columnIndexMap.set(col, index);
    });

    const moveSymbolData = this.GetMoveSymbolData(eliminatePositions);

    // 以每行和moveSymbolData的資料開始落下Symbol
    let promises: Promise<void>[] = [];
    for (const data of moveSymbolData) {
        const { col, row, count } = data;
        const symbolId = plateInfo.PlateSymbol[col].Col[row];
        const columnIndex = columnIndexMap.get(col) ?? 0;
        const visibleRowCount = this.GetVisibleSymbolCount(col);
        const fallDelayTime = Game_Define.SYMBOL_FALL_WAIT_TIME
                            + (this.m_gameView.IsHardStop ? 0 : SYMBOL_FALL_EFFECT_COLUMN_DELAY_TIME * columnIndex)
                            + SYMBOL_FALL_EFFECT_ROW_DELAY_TIME * (visibleRowCount - 1 - row);
        promises.push(this.StartFallSymbol(fallDelayTime, col, row, count, symbolId));

    }

    await Promise.all(promises);

}
//#endregion 表演

//#region 免費遊戲
/**
 * @ch 設定免費遊戲盤面
 */
SetFreeGamePlate() {

}
//#endregion 免費遊戲

