/**
 * @ch 拿到 server 帶來的資料後，將盤面的符號落下到盤面上
 * @description 會先等待 StartSpin 的「掉落出畫面」完成，再把目標位置重設回盤面格點後開始落下
 * @param delayTime 起始延遲時間
 */
private async DropSymbolsToBoardByServerPlateInfo(delayTime: number = 0): Promise<void> {
    try {
        await this.m_dropAllSymbolsOutOfScreenPromise;
    } catch (e) {
        warn("[SlotReel.DropSymbolsToBoardByServerPlateInfo] Wait drop-out failed:", e);
    }

    // 重設盤面位置，避免 targetPos 仍是「掉落出畫面」後的位置
    this.UpdateAllSymbolPositions();

    await this.StartFallAllVisibleSymbolsByServerPlateInfo(delayTime);
    // INV-2 解除綁定 + 原子順序：三個寫入連續同步、無 await 間隔，且固定順序
    // 「先設停 → 清 promise → 清凍結旗標」。先 m_isStop=true 確保凍結解除瞬間 m_isStop 已 true，
    // OnProcess 任一幀都不會落入「兩道閘門皆放行」窗口（消除離開態一幀脫韁）。
    this.m_isStop = true;
    this.m_dropAllSymbolsOutOfScreenPromise = null;
    this.m_isInDropMode = false;
}

