    for (let col = 0; col < Game_Define.COL; ++col) {
        const symbolInfos = this.ConvertSymbolsToSymbolInfos(this.m_plateInfoWithFakeSymbol[col].Col);
        this.m_allColumns[Game_Define.MIDDLE_PLATE_INDEX][col].SetSymbolInfos(symbolInfos, false);

