async TileMatchingAndPatchUp( fillSymbols: Array<Array<number>>, fillMults: Array<Array<number>> )
{
    // 保存 Scatter 特效位置（供後面 tween 用）
    const savedScatterPositions = [...this.m_hiddenScatterPositions];
    // 恢復被 Scatter 動畫隱藏的 symbol，避免 FillSymbol 把它當空位
    for (const pos of this.m_hiddenScatterPositions) {
        this.SetSymbolShow(pos.col, pos.row, true);
        // 確保 sprite 子節點也恢復（tile matching 掉落時會暫時關掉）
        const cell = this.GetSymbolSingleCellFromColRow(pos.col, pos.row);
        if (cell && cell.ThisNode.children[0]) cell.ThisNode.children[0].active = true;
    }
    this.m_hiddenScatterPositions = [];

    let promises: Array<Promise<void>> = new Array<Promise<void>>();
    const pendingFills: Array<{ col: number, row: number, symbol: number, left: number, mult: number, symbolCell: any, isScatter: boolean }> = [];
    const hiddenSpriteNodes: Node[] = [];
    let reelStopSoundIdx = 0; // 0=Reel_Stop, 1=Scatter1, 2=Scatter2, 3=Scatter3
    const middlePlateIndex = Game_Define.MIDDLE_PLATE_INDEX;

    // 天降前統計盤面已有的 Scatter 數量（用於 NearWin 觸發判定）
    // 重置加速倍率，避免 spin 階段的 NearWin 加速殘留影響天降
    for (let i = 0; i < Game_Define.COL; ++i) {
        this.m_nearWinSpeedUp[i] = 1;
    }
    // 掃盤面算實際 Scatter 顆數（用於 NearWin 延遲等視覺效果）
    let dropScatterCount = this.CountAllScattersOnBoard();
    log(`[NearWin DEBUG] TileMatchingAndPatchUp entry: m_scatterCollectCount=${this.m_scatterCollectCount}, boardScatter=${dropScatterCount}, isHasNearWin=${this.m_isHasScatterNearWin}, IsFreeGame=${this.m_gameView.IsFreeGame}`);
    // 已達上限 → 天降不跑 NearWin
    if (this.m_scatterCollectCount >= SCATTER_NEARWIN_MAX_COUNT && this.m_isHasScatterNearWin) {
        this.m_isHasScatterNearWin = false;
        this.StopNearWinSound();
        this.m_gameView.EffectPlate.StopNearWin();
        this.m_gameView.EffectPlate.FreezeAllScattersToStop(); // 達上限：場上 scatter 切回 Stop 並凍結最後一格（不 loop、不還原普通符號）
        this.m_scatterNearWinReachedMax = true; // 本局已達上限，後續天降不再重新觸發 NearWin
    }

    // 先更新節點 Array 順序
    for ( let col = 0; col < Game_Define.COL; col++ )
    {






        this.m_allColumns[middlePlateIndex][ col ].FillSymbol();

        // NearWin 光效移到天降階段（掉落完才觸發）

        let count = 0;
        let multCount = 0;
        for ( let row = Game_Define.ROW - 1; row >= 0; row-- )
        {
            let symbolCell = this.GetSymbolSingleCellFromColRow(col, row);
            if ( symbolCell.ThisNode.active )
            {
                // 有 Spine 特效的 Scatter 隱藏 sprite（掉落過程中只看到 Spine）
                const symId = this.m_allColumns[middlePlateIndex][col].GetSymbolAt(row);
                if (symId === Game_Define.Symbol.Scatter || symId === Game_Define.Symbol.SilverScatter || symId === Game_Define.Symbol.GoldScatter) {
                    const cellWorldPos = symbolCell.ThisNode.getWorldPosition();
                    for (const [_, sSpine] of this.m_gameView.EffectPlate.GetAllScatterAnimationSpines()) {
                        if (sSpine && sSpine.node.active) {
                            const spineWp = sSpine.node.getWorldPosition();
                            if (Math.abs(spineWp.x - cellWorldPos.x) < 10 && Math.abs(spineWp.y - cellWorldPos.y) < 10) {
                                const spriteNode = symbolCell.ThisNode.children[0];
                                if (spriteNode) {
                                    spriteNode.active = false;
                                    hiddenSpriteNodes.push(spriteNode);
                                }
                                break;
                            }
                        }
                    }
                }

                // tile matching
                let beginPos = symbolCell.ThisNode.position;
                let endPos = this.GetMiddleSymbolEmptyNodeFromColRow( col, row ).position;

                let moveY = Math.floor( endPos.y - beginPos.y );

                if ( moveY != 0 )
                {
                    //symbolCell.ThisNode.name = String( col * Game_Define.ROW + row ); // 更新節點名稱 (index)
                    //tools.SetOrderedZindex( symbolCell.ThisNode, col * Game_Define.ROW + ( Game_Define.ROW - 1 - row ) ); // 調整層級
                    let left = Math.abs( moveY ) / this.m_symbolSize.height; // 要移動的格數

                    promises.push( new Promise(
                        ( resolve ) =>
                        {
                            let dropTime = SYMBOL_ENTER_MOVE_TIME * left / Game_Define.ROW;
                            this.CreateDropTween( symbolCell.ThisNode, dropTime, endPos, () => {
                                // NearWin 模式下只有 Scatter 落地才震動
                                const isScatter = symId === Game_Define.Symbol.Scatter || symId === Game_Define.Symbol.SilverScatter || symId === Game_Define.Symbol.GoldScatter;
                                if (this.m_isHasScatterNearWin && isScatter) this.m_gameView.BigHintShake(0.3, Game_Define.NEAR_WIN_SHAKE_DISTANCE);
                                resolve();
                            });

                            for(let layer = 0; layer < Game_Define.EFFECT_LAYER_NUMS; layer++)
                            {
                                let effectNode = this.m_gameView.EffectPlate.GetSymbolNode( col, row, layer );
                                if ( effectNode )
                                {
                                    tools.SetOrderedZindex( effectNode, col * Game_Define.ROW + ( Game_Define.ROW - 1 - row ) ); // 調整動態層級
                                    this.CreateDropTween( effectNode, dropTime, endPos );
                                }
                            }

                            // Scatter 特效跟著掉落（同步 tween，不 reparent）
                            const symIdInner = this.m_allColumns[middlePlateIndex][col].GetSymbolAt(row);
                            log(`[TileMatch] Drop col=${col} row=${row} symId=${symIdInner}`);
                            if (symIdInner === Game_Define.Symbol.Scatter || symIdInner === Game_Define.Symbol.SilverScatter || symIdInner === Game_Define.Symbol.GoldScatter) {
                                const cellWorldPos = symbolCell.ThisNode.getWorldPosition();
                                for (const [key, sSpine] of this.m_gameView.EffectPlate.GetAllScatterAnimationSpines()) {
                                    if (sSpine && sSpine.node.active && !sSpine.node['_reparented']) {
                                        const spineWorldPos = sSpine.node.getWorldPosition();
                                        if (Math.abs(spineWorldPos.x - cellWorldPos.x) < 30 && Math.abs(spineWorldPos.y - cellWorldPos.y) < 30) {
                                            // 標記為正在掉落，讓 PlayScatterStopAnimation 跳過它建新 Spine
                                            sSpine.node['_reparented'] = true;
                                            // 從 map 移除舊 key（tween 結束後 RebuildKeys 會重新加入）
                                            this.m_gameView.EffectPlate.GetAllScatterAnimationSpines().delete(key);
                                            // 計算目標世界座標（EmptyNode 的位置）並轉成 Spine 的 local position
                                            const targetWorldPos = this.GetSymbolInitWorldPositionFromColRow(col, row);
                                            const spineParent = sSpine.node.parent;
                                            const targetLocalPos = new Vec3();
                                            spineParent.inverseTransformPoint(targetLocalPos, targetWorldPos);
                                            // 用同步 tween 移到目標 local position，結束後清 flag + 重新加入 map
                                            const capturedSpine = sSpine;
                                            tween(sSpine.node)
                                                .to(dropTime, { position: targetLocalPos }, { easing: "sineIn" })
                                                .call(() => {
                                                    delete capturedSpine.node['_reparented'];
                                                    this.m_gameView.EffectPlate.AddScatterSpineToMap(capturedSpine);
                                                })
                                                .start();
                                            break;
                                        }
                                    }
                                }
                            }

                            // Target 特效跟著掉落（同步 tween，跟 Scatter 一樣）
                            if (symIdInner === Game_Define.Symbol.Target || symIdInner === Game_Define.Symbol.GoldTarget) {
                                const cellWorldPos = symbolCell.ThisNode.getWorldPosition();
                                for (const [key, info] of this.m_gameView.EffectPlate.GetAllTargetStopNodes()) {
                                    if (info && info.node.active) {
                                        const spineWorldPos = info.node.getWorldPosition();
                                        if (Math.abs(spineWorldPos.x - cellWorldPos.x) < 30 && Math.abs(spineWorldPos.y - cellWorldPos.y) < 30) {
                                            this.m_gameView.EffectPlate.GetAllTargetStopNodes().delete(key);
                                            const targetWorldPos = this.GetSymbolInitWorldPositionFromColRow(col, row);
                                            const spineParent = info.node.parent;
                                            const targetLocalPos = new Vec3();
                                            spineParent.inverseTransformPoint(targetLocalPos, targetWorldPos);
                                            const capturedInfo = info;
                                            const capturedPosition = Common.GetPositionFromColRow(col, row);
                                            tween(info.node)
                                                .to(dropTime, { position: targetLocalPos }, { easing: "sineIn" })
                                                .call(() => {
                                                    this.m_gameView.EffectPlate.RegisterTargetStopNode(capturedPosition, capturedInfo.node, capturedInfo.prefabKey);
                                                })

