private GetFakeReelRandomSymbol(reelIndex: number, isGetNext: boolean = false): number {
    let gameType = this.m_gameView.IsFreeGame ? FeverGameType.FreeGame : FeverGameType.MainGame;
    let symbolId = -1;
    let seed = this.m_nowFakeReelPositions[reelIndex];
    if (isGetNext) {
        const offset = this.GetDirectionMultiplier();
        seed = this.GetRealFakeReelIndex(seed + offset);
        this.m_nowFakeReelPositions[reelIndex] = seed;
    }
    eventManager.Dispatch(FAKE_REEL_MANAGER_EVENT.GET_RANDOM_SYMBOL, gameType, reelIndex, seed, (symbol: number) => {
        symbolId = symbol;
    });

    if (symbolId < 0 || symbolId >= Game_Define.Symbol.MAX) {
        symbolId = this.CreateDefaultFakeReelRandomSymbol();

    }
    return symbolId;
}
