private GetColumn(col: number): ColumnSymbol | null {
    if (!this.m_allColumns || this.m_allColumns.length === 0 || col < 0 || col >= Game_Define.COL) {
        return null;
    }

    const middlePlateIndex = Game_Define.MIDDLE_PLATE_INDEX;
    if (middlePlateIndex >= this.m_allColumns.length) {
        return null;
    }

    return this.m_allColumns[middlePlateIndex][col] || null;
}

/**
 * 根據行列座標取得對應的 SingleCell
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param row 行索引 (0 ~ visibleSymbolCount-1)
 * @returns SingleCell 或 null
 */
GetSingleCellFromColRow(col: number, row: number): SingleCell | null {
    const column = this.GetColumn(col);
    return column ? column.GetSingleCell(row) : null;
}

/**
 * 根據行列座標取得對應的符號 Node
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param row 行索引 (0 ~ visibleSymbolCount-1)
 * @returns Node 或 null
 */
GetSymbolNodeFromColRow(col: number, row: number): Node | null {
    const column = this.GetColumn(col);
    return column ? column.GetSymbolNodeAt(row) : null;
}

/**
 * 根據行列座標取得對應的 SingleCell
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param row 行索引 (0 ~ visibleSymbolCount-1)
 * @returns SingleCell 或 null
 */
GetSymbolSingleCellFromColRow(col: number, row: number): SingleCell | null {
    const column = this.GetColumn(col);
    return column ? column.GetSymbolSingleCellAt(row) : null;
}
